<?php

namespace Database\Seeders;

use App\Models\Faq;
use App\Models\FaqCategory;
use Illuminate\Database\Seeder;

class FaqSeederV2 extends Seeder
{
    public function run(): void
    {
        $categories = FaqCategory::all()->keyBy('name');
        $existingQuestions = Faq::pluck('question')->map(fn($q) => trim($q))->toArray();

        $newFaqs = [
            ['category_name' => 'Consultas Generales', 'question' => '¿Qué trámites puedo realizar por la plataforma web y cuáles requieren mi presencia en ventanilla?', 'answer' => 'Por la plataforma web (VIVA o Mesa de Partes Virtual) puedes tramitar casi todo: inscripciones de derechohabientes, solicitudes de lactancia, maternidad e incapacidad temporal. Solo casos muy complejos (como impugnaciones especiales o cuando el sistema digital falla reiteradamente) requieren que vayas físicamente a una oficina de seguros (OSPE).', 'keywords' => '["trámites", "realizar", "plataforma", "cuáles", "requieren", "presencia", "ventanilla"]'],
            ['category_name' => 'Consultas Generales', 'question' => '¿El cambio de domicilio que realicé en la plataforma VIVA es inmediato o requiere alguna validación adicional?', 'answer' => 'El cambio de dirección para asignarte un nuevo centro médico requiere una validación de tus datos de identidad. Recuerda que por motivos personales o laborales este cambio excepcional mediante el Formulario 1010 sólo se puede realizar una vez por año calendario y por un periodo máximo de 6 meses.', 'keywords' => '["cambio", "domicilio", "realicé", "plataforma", "viva", "inmediato", "requiere", "alguna"]'],
            ['category_name' => 'Consultas Generales', 'question' => '¿Cómo puedo consultar el estado de un trámite que ya realicé?', 'answer' => 'Puedes ingresar a la plataforma VIVA con tu usuario o utilizar la opción de consulta pública de trámites de la web de EsSalud colocando tu número de documento o el código NIT (Número Interno de Trámite) que te dieron al iniciar el expediente.', 'keywords' => '["cómo", "consultar", "estado", "trámite", "realicé"]'],
            ['category_name' => 'Consultas Generales', 'question' => '¿Cómo me registro por primera vez en la plataforma VIVA?', 'answer' => 'Entras a la web de la Plataforma VIVA, seleccionas la opción \"Registrarse\", eliges si eres asegurado o empresa, completas tus datos personales (DNI, dígito verificador, datos de contacto) y creas tu contraseña. Te llegará un correo para activar la cuenta.', 'keywords' => '["cómo", "registro", "primera", "plataforma", "viva"]'],
            ['category_name' => 'Consultas Generales', 'question' => '¿Cómo recupero mi contraseña de VIVA si no me llega el correo?', 'answer' => 'Primero revisa tu carpeta de \"Correo no deseado\" o \"Spam\". Si sigue sin llegar, debes usar la opción \"Olvidé mi contraseña\" asegurándote de colocar el correo exacto con el que te registraste. Si el problema persiste, tendrás que comunicarte al soporte técnico de EsSalud en Línea.', 'keywords' => '["cómo", "recupero", "contraseña", "viva", "llega", "correo"]'],
            ['category_name' => 'Consultas Generales', 'question' => '¿Qué hago si no me llegan las credenciales de acceso a mi correo?', 'answer' => 'Puede deberse a que el correo que registraste tenía un error de digitación. Debes reportarlo a los canales de atención al asegurado (por ejemplo, escribiendo a atencionalasegurado@essalud.gob.pe) para que un asesor limpie tu registro y puedas volver a crear la cuenta correctamente.', 'keywords' => '["hago", "llegan", "credenciales", "acceso", "correo"]'],
            ['category_name' => 'Consultas Generales', 'question' => '¿Cómo puedo adjuntar un documento en VIVA? ¿Qué formatos y tamaños permite?', 'answer' => 'Dentro del trámite que estés realizando verás un botón para subir archivos o \"Añadir gasto/documento\". El sistema permite por lo general formatos estándar como PDF e imágenes en JPG o PNG. El tamaño máximo suele ser de 2MB a 5MB por archivo para evitar que la plataforma colapse.', 'keywords' => '["cómo", "adjuntar", "documento", "viva", "formatos", "tamaños", "permite"]'],
            ['category_name' => 'Consultas Generales', 'question' => '¿Qué hago si VIVA no me permite adjuntar un PDF?', 'answer' => 'Si te sale un error, suele ser por dos motivos: el archivo pesa más de lo permitido o el nombre del archivo contiene caracteres extraños (como tildes, comas o la letra Ñ). Cambia el nombre del PDF a algo muy simple (ejemplo: documentosubside.pdf) e imprímelo si es muy pesado antes de volver a intentar.', 'keywords' => '["hago", "viva", "permite", "adjuntar"]'],
            ['category_name' => 'Consultas Generales', 'question' => '¿Cómo solicito el cambio de mi número de celular o correo registrado en VIVA?', 'answer' => 'Puedes hacerlo ingresando a la configuración de tu perfil dentro de la misma plataforma VIVA si recuerdas tu contraseña. Si no puedes acceder, deberás comunicarte con la Central de Orientación y Consultas de EsSalud para que un asesor valide tu identidad por teléfono o ventanilla y actualiza tus datos de contacto.', 'keywords' => '["cómo", "solicito", "cambio", "número", "celular", "correo", "registrado", "viva"]'],
            ['category_name' => 'Consultas Generales', 'question' => '¿Cómo puedo dar de baja a un representante de mi empresa en VIVA?', 'answer' => 'El usuario administrador de la empresa debe ingresar a la sección de configuración de accesos de la Plataforma VIVA Corporativa, seleccionar al representante o usuario secundario y darle clic en \"Eliminar\" o \"Dar de baja\", quitándole de inmediato los permisos para hacer trámites en nombre de la empresa.', 'keywords' => '["cómo", "baja", "representante", "empresa", "viva"]'],
            ['category_name' => 'Consultas Generales', 'question' => '¿Cómo recupero la contraseña de mi cuenta de empresa en VIVA?', 'answer' => 'En la pantalla de acceso corporativo de VIVA, selecciona \"Olvidé mi contraseña de empresa\". El sistema te pedirá el RUC de la empresa y los datos del representante legal. El enlace de restablecimiento se enviará al correo institucional que se registró originalmente ante EsSalud.', 'keywords' => '["cómo", "recupero", "contraseña", "cuenta", "empresa", "viva"]'],
            ['category_name' => 'Consultas Generales', 'question' => '¿Qué es la Mesa de Partes Digital y para qué sirve?', 'answer' => 'Es una ventanilla virtual oficial que funciona a través de internet. Sirve para que cualquier ciudadano o empresa pueda presentar solicitudes, cartas, formularios o documentos de manera digital sin tener que viajar o hacer colas en una oficina física de EsSalud.', 'keywords' => '["mesa", "partes", "digital", "sirve"]'],
            ['category_name' => 'Consultas Generales', 'question' => '¿Cómo me registro en la Mesa de Partes Digital?', 'answer' => 'Entras al portal web de la Mesa de Partes Digital de EsSalud, haces clic en \"Crear cuenta\", rellenas tus datos personales completos, ingresar un correo electrónico válido, creas una clave de acceso y confirmas tu registro mediante el enlace que te llegará a tu bandeja de entrada.', 'keywords' => '["cómo", "registro", "mesa", "partes", "digital"]'],
            ['category_name' => 'Consultas Generales', 'question' => '¿Cómo activo mi cuenta en la Mesa de Partes Digital si no recibió el correo?', 'answer' => 'Espera unos minutos y revisa la sección de \"Spam\" o \"Promociones\". Si sigue sin aparecer, vuelve a la página de ingreso e intenta registrarte otra vez; si el sistema te dice que tu DNI ya está registrado, dale clic a \"Reenviar correo de activación\" para que el código sea enviado nuevamente.', 'keywords' => '["cómo", "activo", "cuenta", "mesa", "partes", "digital", "recibió", "correo"]'],
            ['category_name' => 'Consultas Generales', 'question' => '¿Cómo recupero mi contraseña de la Mesa de Partes Digital?', 'answer' => 'En la página web de ingreso de la Mesa de Partes Digital, selecciona el enlace \"¿Olvidó su contraseña?\". Escribe tu número de DNI, y el sistema te enviará de inmediato un mensaje a tu correo electrónico con las instrucciones precisas para generar una nueva clave.', 'keywords' => '["cómo", "recupero", "contraseña", "mesa", "partes", "digital"]'],
            ['category_name' => 'Consultas Generales', 'question' => '¿Cuál es el horario de funcionamiento de la Mesa de Partes Digital?', 'answer' => 'Puedes registrar y subir tus documentos las 24 horas del día, los 7 días de la semana. Sin embargo, ten en cuenta que los papeles cargados fuera del horario oficial (usualmente después de las 4:30 p.m. o en días feriados y fines de semana) se consideran presentados legalmente a primera hora del día hábil siguiente.', 'keywords' => '["cuál", "horario", "funcionamiento", "mesa", "partes", "digital"]'],
            ['category_name' => 'Consultas Generales', 'question' => '¿Qué documentos puedo presentar en la Mesa de Partes Digital?', 'answer' => 'Puedes presentar cualquier solicitud formal de carácter administrativo, solicitudes de información pública, cartas dirigidas a las gerencias asistenciales y expedientes de trámites de seguros que no tengan una plataforma web específica de atención.', 'keywords' => '["documentos", "presentar", "mesa", "partes", "digital"]'],
            ['category_name' => 'Consultas Generales', 'question' => '¿Cómo creo una cuenta en Mi Consulta?', 'answer' => 'Entras a la web oficial de \"Mi Consulta EsSalud\" o descargas la aplicación oficial en tu teléfono celular, seleccionas \"Registrarse\", digitas los datos de tu DNI (número, fecha de emisión) y configuras tus datos de contacto personales junto a una clave de seguridad.', 'keywords' => '["cómo", "creo", "cuenta", "consulta"]'],
            ['category_name' => 'Consultas Generales', 'question' => '¿Cómo recupero mi contraseña de Mi Consulta?', 'answer' => 'En el aplicativo o página web de Mi Consulta, pulsa la opción \"¿Olvidaste tu contraseña?\". Valida tu identidad ingresando los datos de tu DNI que te solicite la plataforma y recibirás un enlace de restauración en el correo electrónico que vinculaste al sistema.', 'keywords' => '["cómo", "recupero", "contraseña", "consulta"]'],
            ['category_name' => 'Consultas Generales', 'question' => '¿Qué puedo hacer en la plataforma Mi Consulta?', 'answer' => 'Es tu portal de salud personal. Ahí puedes revisar tus citas médicas programadas, ver en qué centro te atiendes, chequear tus referencias médicas, revisar las recetas que te han recetado los doctores y ver las constancias de tus descansos médicos (CITT).', 'keywords' => '["plataforma", "consulta"]'],
            ['category_name' => 'Consultas Generales', 'question' => '¿Cómo veo mis recetas médicas en Mi Consulta?', 'answer' => 'Una vez dentro de tu cuenta en Mi Consulta, dirígete al módulo de \"Historial Médico\" o \"Mis Recetas\". Ahí aparecerá la lista completa de los medicamentos que te prescribió el doctor en tus consultas asistenciales, junto con las indicaciones de cómo tomarlos.', 'keywords' => '["cómo", "recetas", "médicas", "consulta"]'],
            ['category_name' => 'Consultas Generales', 'question' => '¿Cómo veo los resultados de mis exámenes auxiliares en Mi Consulta?', 'answer' => 'En el menú principal de la plataforma, ingresa a la sección \"Exámenes de Laboratorio\" o \"Ayuda al Diagnóstico\". El sistema te mostrará la lista de análisis de sangre, placas u otros exámenes que te hayas realizado en los hospitales de EsSalud listos para visualizar o descargar.', 'keywords' => '["cómo", "resultados", "exámenes", "auxiliares", "consulta"]'],
            ['category_name' => 'Consultas Generales', 'question' => '¿Cómo veo y descargo mi CITT en Mi Consulta?', 'answer' => 'Ingresa a la pestaña llamada \"Mis Descansos Médicos\" o \"Certificados CITT\". Si tu descanso ya fue validado y cargado por el médico o el área de control, verás el código oficial del CITT y tendrás un botón para descargarlo en formato PDF e imprimirlo a tu empleador.', 'keywords' => '["cómo", "descargo", "citt", "consulta"]'],
            ['category_name' => 'Consultas Generales', 'question' => '¿Cómo consulto el estado de una referencia médica en Mi Consulta?', 'answer' => 'Vas a la sección de \"Referencias\". El sistema te mostrará si tu solicitud para atenderte en un hospital de mayor complejidad ya fue aceptada, qué hospital la recibió y si ya te asignaron la fecha y hora para la cita con el médico especialista.', 'keywords' => '["cómo", "consulto", "estado", "referencia", "médica", "consulta"]'],
            ['category_name' => 'Consultas Generales', 'question' => '¿Qué datos necesito obligatoriamente para crear mi cuenta en VIVA?', 'answer' => 'Necesitas tener a la mano: tu número de DNI, el dígito verificador del DNI (el número que está al costado de tu foto en la parte superior derecha), tu fecha de nacimiento, un número de teléfono celular propio y un correo electrónico personal activo.', 'keywords' => '["datos", "obligatoriamente", "crear", "cuenta", "viva"]'],
            ['category_name' => 'Consultas Generales', 'question' => '¿Cómo debe ser mi contraseña para que el sistema la acepte?', 'answer' => 'Para cumplir con los estándares de seguridad modernos, tu contraseña debe tener al menos 8 caracteres de largo e incluir obligatoriamente una combinación de: letras mayúsculas, letras minúsculas, números y al menos un símbolo o carácter especial (como un punto, un guión o un arroba). Lo más común es que no hayas hecho clic en el enlace de activación que te llegó al correo electrónico al terminar tu registro. Si ya lo hiciste, verifica que no tengas la tecla de mayúsculas activada por error o que no estés confundiendo números con letras al escribir tu clave.', 'keywords' => '["cómo", "debe", "contraseña", "sistema", "acepte"]'],
            ['category_name' => 'Consultas Generales', 'question' => '¿Qué hago si olvido mi contraseña de acceso?', 'answer' => 'No intentes adivinar muchas veces porque el sistema podría bloquear a tu usuario por seguridad. Simplemente dale clic al botón \"Olvidé mi contraseña\" que aparece abajo de la caja de texto de ingreso para que el sistema te guíe en su restablecimiento.', 'keywords' => '["hago", "olvido", "contraseña", "acceso"]'],
            ['category_name' => 'Consultas Generales', 'question' => '¿Cómo me enteré si mi solicitud fue aprobada o rechazada?', 'answer' => 'Al momento de llenar tus formularios (como el Formulario 1010 o el Anexo 10), firmas una declaración jurada donde autorizas expresamente a EsSalud a notificar por medios digitales. Por lo tanto, te enviarán la resolución oficial directamente al correo electrónico que registraste.', 'keywords' => '["cómo", "enteré", "solicitud", "aprobada", "rechazada"]'],
            ['category_name' => 'Consultas Generales', 'question' => '¿Qué es la plataforma VIVA y qué trámites puedo hacer ahí?', 'answer' => 'VIVA (Ventanilla Integrada Virtual del Asegurado) es la plataforma oficial de EsSalud diseñada para evitar que hagas trámites presenciales. Ahí puedes afiliar a tu esposa, conviviente o hijos, actualizar tus datos de domicilio y gestionar el cobro de tus subsidios económicos.', 'keywords' => '["plataforma", "viva", "trámites"]'],
            ['category_name' => 'Consultas Generales', 'question' => '¿Qué es el NIT (Número Interno de Trámite) y para qué sirve?', 'answer' => 'El NIT es un código de números único que funciona como el \"DNI de tu trámite\". Sirve para que puedas rastrear digitalmente tu expediente en la web y saber con exactitud en qué oficina se encuentra, qué médico lo está evaluando o si ya está listo para pagarse.', 'keywords' => '["número", "interno", "trámite", "sirve"]'],
            ['category_name' => 'Consultas Generales', 'question' => '¿Dónde encuentro tutoriales en video para usar las plataformas de EsSalud?', 'answer' => 'Los encuentras en el canal oficial de YouTube de EsSalud (\"EsSalud Perú\") o directamente dentro de las secciones de ayuda y guías de usuario del Portal Institucional (www.essalud.gob.pe).', 'keywords' => '["dónde", "encuentro", "tutoriales", "video", "usar", "plataformas", "essalud"]'],
            ['category_name' => 'Consultas Generales', 'question' => '¿Qué formatos de archivo soporta la plataforma VIVA para subir documentos?', 'answer' => 'Soporta documentos digitalizados en formato PDF e imágenes en formato JPG o PNG. Se recomienda que los escanees en blanco y negro o con resolución moderada para que las letras sean legibles pero el archivo no sea demasiado pesado.', 'keywords' => '["formatos", "archivo", "soporta", "plataforma", "viva", "subir", "documentos"]'],
            ['category_name' => 'Consultas Generales', 'question' => '¿Para qué sirve el botón “RELLAMAR” en la plataforma VIVA?', 'answer' => 'Es una opción diseñada para trámites que se quedaron \"trabados\" o que requieren una atención o revaluación debido a un error técnico del sistema o una observación que ya subsanadas, permitiendo reactivar el flujo de revisión de tu expediente.', 'keywords' => '["sirve", "botón", "rellamar", "plataforma", "viva"]'],
            ['category_name' => 'Consultas Generales', 'question' => '¿Cómo activo mi cuenta en la plataforma VIVA?', 'answer' => 'Al terminar tu registro, el sistema te envía un correo electrónico de manera automática. Debes abrir ese mensaje y hacer clic en el botón grande o enlace que dice \"Activar Cuenta\". Tienes un tiempo limitado para hacerlo antes de que el enlace expire.', 'keywords' => '["cómo", "activo", "cuenta", "plataforma", "viva"]'],
            ['category_name' => 'Consultas Generales', 'question' => '¿Qué plazo tengo para corregir un trámite observado en VIVA?', 'answer' => 'Por regla general administrativa, cuentas con un plazo habitual de 2 a 5 días hábiles (según la directiva específica del trámite) para subir los documentos correctos o subsanar la observación desde que recibes el correo de alerta. Si dejas pasar el tiempo, tu trámite será rechazado por abandono.', 'keywords' => '["plazo", "corregir", "trámite", "observado", "viva"]'],
            ['category_name' => 'Consultas Generales', 'question' => '¿Qué hago si no puedo recuperar mi contraseña en ninguna plataforma?', 'answer' => 'Debes acudir de manera presencial a la Oficina de Seguros y Prestaciones Económicas (OSPE) o al módulo de atención al asegurado más cercano portando tu DNI físico para que el personal del centro resetee manualmente tu usuario y limpie tu historial de accesos.', 'keywords' => '["hago", "recuperar", "contraseña", "ninguna", "plataforma"]'],
            ['category_name' => 'Consultas Generales', 'question' => '¿Cómo puedo reportar un problema técnico con una plataforma de EsSalud?', 'answer' => 'Puedes llamar por teléfono al número de soporte institucional (411-8000 en Lima), usar la opción virtual del Libro de Reclamaciones del portal web o enviar un correo detallado con las capturas de pantalla del error técnico a atencionalasegurado@essalud.gob.pe', 'keywords' => '["cómo", "reportar", "problema", "técnico", "plataforma", "essalud"]'],
            ['category_name' => 'Consultas Generales', 'question' => '¿Cómo puedo saber cuál es mi centro de salud asignado?', 'answer' => 'El policlínico o establecimiento médico se te asigna de forma automática tomando como base exclusiva la dirección domiciliaria que aparece registrada en tu DNI físico.', 'keywords' => '["cómo", "cuál", "centro", "salud", "asignado"]'],
            ['category_name' => 'Consultas Generales', 'question' => '¿Cómo verifico si mi seguro de EsSalud está activo?', 'answer' => 'Ingresa a la página oficial: www.essalud.gob.pe. Busca y dale clic al botón \"¿Dónde me atiendo?\" ubicado abajo a la izquierda. Digita los datos completos del asegurado (nombres o número de DNI) y presiona \"Consultar\". El sistema te mostrará si estás activo y cuál es tu centro de salud.', 'keywords' => '["cómo", "verifico", "seguro", "essalud", "está", "activo"]'],
            ['category_name' => 'Consultas Generales', 'question' => '¿Qué es el dígito verificador (CUI) y dónde lo encuentro en mi DNI?', 'answer' => 'Es el número único que se encuentra en tu DNI físico al costado derecho del número principal de tu documento, justo después del guión (ejemplo: si tu DNI es 12345678-9, el dígito verificador es el 9). Sirve para confirmar que el DNI es real.', 'keywords' => '["dígito", "verificador", "dónde", "encuentro"]'],
            ['category_name' => 'Consultas Generales', 'question' => '¿Cómo consulto la vigencia de mi cobertura en EsSalud?', 'answer' => 'Lo haces a través del mismo portal de \"¿Dónde me atiendo?\". En el resultado de la consulta verás una casilla que indica \"Vigencia de atención\", donde se muestran las fechas exactas de inicio y fin de tu cobertura acreditada.', 'keywords' => '["cómo", "consulto", "vigencia", "cobertura", "essalud"]'],
            ['category_name' => 'Consultas Generales', 'question' => '¿Dónde encuentro la oficina OSPE más cercana a mi domicilio?', 'answer' => 'La lista de Oficinas de Seguros y Prestaciones Económicas (OSPE) con sus direcciones exactas a nivel nacional se encuentra publicada en el portal web institucional de EsSalud, ubicadas usualmente en las capitales de provincia o distritos céntricos.', 'keywords' => '["dónde", "encuentro", "oficina", "ospe", "cercana", "domicilio"]'],
            ['category_name' => 'Consultas Generales', 'question' => '¿Cuál es el horario de atención de las oficinas OSPE?', 'answer' => 'El horario habitual de atención al público en las oficinas físicas presenciales es de lunes a viernes desde las 8:00 a.m. hasta las 4:00 p.m. o 4:30 p.m. (horas de oficina del sector público), no laborando los días sábados, domingos ni feriados de calendario.', 'keywords' => '["cuál", "horario", "atención", "oficinas", "ospe"]'],
            ['category_name' => 'Consultas Generales', 'question' => '¿Qué trámites puedo hacer de forma presencial en una OSPE?', 'answer' => 'Puedes hacer consultas complejas sobre acreditación bloqueada, registrar matrimonios celebrados en el extranjero, resolver deudas de aportes de empleadores, o tramitar la validación de subsidios de expedientes especiales en físico que hayan sido observados en la web.', 'keywords' => '["trámites", "forma", "presencial", "ospe"]'],
            ['category_name' => 'Consultas Generales', 'question' => '¿Necesito cita previa para ir a una OSPE?', 'answer' => 'Por lo general, la atención es por orden de llegada mediante la entrega de tickets en la ventanilla de recepción. Sin embargo, se recomienda revisar la web institucional por si se activa temporalmente el sistema de citas virtuales para trámites administrativos.', 'keywords' => '["cita", "previa", "ospe"]'],
            ['category_name' => 'Consultas Generales', 'question' => '¿Cómo actualizo mi domicilio o mis datos personales?', 'answer' => 'Debes presentar el Formulario 1010 (versión 06\) correctamente llenado y firmado. Si trabajas para una empresa, debes entregarle el formulario y tus papeles de sustento a tu empleador para que él lo actualice a través del T-Registro de la SUNAT.', 'keywords' => '["cómo", "actualizo", "domicilio", "datos", "personales"]'],
            ['category_name' => 'Consultas Generales', 'question' => '¿Qué hago si no cuento con acreditación vigente para la atención médica?', 'answer' => 'Si estás trabajando pero el hospital te dice que no apareces activo, debes acudir a una oficina OSPE portando tu DNI y tus boletas de pago recientes para demostrar que tu empleador te está reteniendo los aportes y el personal te active manualmente en el sistema.', 'keywords' => '["hago", "cuento", "acreditación", "vigente", "atención", "médica"]'],
            ['category_name' => 'Consultas Médicas', 'question' => '¿Cómo saco una cita médica en EsSalud?', 'answer' => 'Puedes solicitarla llamando por teléfono al canal de \"EsSalud en Línea\" de tu región o departamento. También puedes hacerlo de forma digital a través de la aplicación móvil Mi Consulta EsSalud o acercándote directamente a los módulos de citas de tu policlínico asignado.', 'keywords' => '["cómo", "saco", "cita", "médica", "essalud"]'],
            ['category_name' => 'Consultas Médicas', 'question' => '¿Cuáles son los canales para sacar una cita médica?', 'answer' => 'Los canales principales son: la central telefónica de EsSalud en Línea de tu provincia, la aplicación digital o página web oficial Mi Consulta, y de manera presencial directamente en las ventanillas de Admisión de tu centro médico asistencial.', 'keywords' => '["cuáles", "canales", "sacar", "cita", "médica"]'],
            ['category_name' => 'Consultas Médicas', 'question' => '¿Cuál es el número de EsSalud en Línea de mi departamento para sacar cita por teléfono?', 'answer' => 'Si estás en Lima, el número central es el 411-8000. Para las provincias, cada región tiene su propio número oficial de EsSalud en Línea: Arequipa: (054) 22-6969; Cusco: (084) 58-1150; La Libertad: (044) 48-5030; Lambayeque: (074) 48-1060; Piura: (073) 28-4760; Ica: (056) 58-1060.', 'keywords' => '["cuál", "número", "essalud", "línea", "departamento", "sacar", "cita", "teléfono"]'],
            ['category_name' => 'Consultas Médicas', 'question' => '¿Cuánto tiempo antes debo llegar a mi cita médica?', 'answer' => 'Se recomienda que llegues al menos 30 minutos antes de la hora programada si tu cita es común, y hasta 45 minutos antes si debes pasar primero por el área de triaje para que te midan la presión y el peso, evitando perder tu turno.', 'keywords' => '["cuánto", "tiempo", "antes", "debo", "llegar", "cita", "médica"]'],
            ['category_name' => 'Consultas Médicas', 'question' => '¿Qué documentos necesito para asistir a mi cita médica?', 'answer' => 'Solo necesitas llevar tu DNI físico y vigente. Si eres extranjero, debes presentar tu Carnet de Extranjería o Pasaporte registrado en el sistema. No es necesario llevar papeles impresos de acreditación a menos que el sistema informático del hospital sufra una caída.', 'keywords' => '["documentos", "asistir", "cita", "médica"]'],
            ['category_name' => 'Consultas Médicas', 'question' => '¿Cómo cancelar o reprogramar una cita médica?', 'answer' => 'Debes hacerlo llamando a la central de EsSalud en Línea o a través del aplicativo Mi Consulta con un mínimo de 48 horas de anticipación. Así permites que el sistema libere ese cupo médico y otra persona que lo necesite con urgencia pueda atenderse.', 'keywords' => '["cómo", "cancelar", "reprogramar", "cita", "médica"]'],
            ['category_name' => 'Prestaciones Económicas', 'question' => '¿Qué prestaciones económicas ofrece EsSalud?', 'answer' => 'EsSalud te da cuatro tipos de ayudas económicas: el subsidio por incapacidad temporal (cuando te enfermas o accidentas y no puedes trabajar), el subsidio por maternidad (cuando das a luz y estás de descanso), el subsidio por lactancia (un dinero fijo por cada hijo que nace vivo) y la prestación por sepelio (te reembolsan los gastos del entierro de un familiar asegurado).', 'keywords' => '["prestaciones", "económicas", "ofrece", "essalud"]'],
            ['category_name' => 'Prestaciones Económicas', 'question' => '¿Qué se considera exactamente como una prestación económica?', 'answer' => 'Son los pagos en dinero que EsSalud te da cuando estás en una situación especial que te impide trabajar o que genera gastos: enfermedad, maternidad, nacimiento de un hijo o fallecimiento de un familiar asegurado. Son cuatro: incapacidad temporal, maternidad, lactancia y sepelio.', 'keywords' => '["considera", "exactamente", "prestación", "económica"]'],
            ['category_name' => 'Prestaciones Económicas', 'question' => '¿Para qué trámites de subsidio se utiliza el Formulario 1040?', 'answer' => 'El Formulario 1040 es el \"comodín\" de las prestaciones económicas. Lo usas para solicitar casi todos los subsidios: Incapacidad Temporal (descanso médico), Maternidad (descanso pre y post parto), Lactancia y Sepelio. Básicamente, es la solicitud oficial para pedir tu dinero.', 'keywords' => '["trámites", "subsidio", "utiliza", "formulario"]'],
            ['category_name' => 'Prestaciones Económicas', 'question' => '¿Qué sección debe llenar y firmar mi empleador si solicita el reembolso de mi descanso médico?', 'answer' => 'Si tu empleador te pagó el subsidio y quiere que EsSalud le devuelva la plata, él debe llenar la sección de Datos del Empleador (Pago por Empleador con Cargo a Reembolso). Ahí va su RUC y la firma del representante legal o del área de recursos humanos. Además, tú como trabajador debes firmar la declaración jurada de haber recibido ese dinero de la empresa.', 'keywords' => '["sección", "debe", "llenar", "firmar", "empleador", "solicita", "reembolso", "descanso"]'],
            ['category_name' => 'Prestaciones Económicas', 'question' => '¿Cómo autorizo a otra persona para que presente mi formulario 1040 en EsSalud sin usar carta poder?', 'answer' => 'Si el monto del subsidio es pequeño (generalmente hasta S/ 2,750 / 0.5 UIT), no necesitas carta poder con notario. Basta con que tu autorizado lleve su DNI y entregue el formulario, siempre y cuando esté firmado por ti. Incluso a veces te piden una Carta Poder Simple, aunque a veces solo con tu firma en el formulario y tu DNI basta. Sin embargo, para montos altos, el notario sí es obligatorio.', 'keywords' => '["cómo", "autorizo", "otra", "persona", "presente", "formulario", "essalud", "usar"]'],
            ['category_name' => 'Prestaciones Económicas', 'question' => '¿Qué documentos son obligatorios para solicitar cualquier prestación económica?', 'answer' => 'El Formulario 1040 (siempre), el DNI del solicitante y del titular (si es diferente), y el documento que sustente la contingencia (CITT para enfermedad, acta de nacimiento para lactancia, acta de defunción para sepelio, etc.).', 'keywords' => '["documentos", "obligatorios", "solicitar", "cualquier", "prestación", "económica"]'],
            ['category_name' => 'Prestaciones Económicas', 'question' => '¿Qué sistemas usa EsSalud para aprobar mi subsidio y cómo consultar mi estado con el NIT?', 'answer' => 'EsSalud procesa tu información cruzando datos entre la plataforma VIVA, el sistema de control de prestaciones y las declaraciones de planillas de SUNAT. Para ver cómo va tu caso, entras al portal de consultas web de EsSalud colocando el código NIT (Número Interno de Trámite) que viene impreso en tu cargo de recepción.', 'keywords' => '["sistemas", "essalud", "aprobar", "subsidio", "cómo", "consultar", "estado"]'],
            ['category_name' => 'Prestaciones Económicas', 'question' => '¿Qué es la plataforma VIVA y para qué sirve en relación con los pagos?', 'answer' => 'Sirve como el canal directo de comunicación entre el asegurado, el empleador y EsSalud para autorizar el cobro de dinero. Permite ingresar los expedientes de maternidad, lactancia y descansos médicos para que el sistema procese y deposite los fondos correspondientes en tu banco o mediante reembolso a tu empresa.', 'keywords' => '["plataforma", "viva", "sirve", "relación", "pagos"]'],
            ['category_name' => 'Prestaciones Económicas', 'question' => '¿Cómo calculan los decimales o el redondeo en los subsidios?', 'answer' => 'El subsidio diario se calcula con tu sueldo promedio, y puede salir un número con decimales. EsSalud no redondea hacia arriba. Generalmente toman el valor exacto para el cálculo total de días. Si el resultado tiene muchos decimales, el sistema lo procesa así.', 'keywords' => '["cómo", "calculan", "decimales", "redondeo", "subsidios"]'],
            ['category_name' => 'Prestaciones Económicas', 'question' => '¿Se incluyen las gratificaciones de julio y diciembre en el cálculo del subsidio diario?', 'answer' => 'No. Las gratificaciones (Fiestas Patrias y Navidad) no se incluyen en el cálculo del subsidio diario. Solo se toman en cuenta las remuneraciones regulares (sueldo base, horas extras, bonificaciones de carácter permanente).', 'keywords' => '["incluyen", "gratificaciones", "julio", "diciembre", "cálculo", "subsidio", "diario"]'],
            ['category_name' => 'Subsidio por Lactancia', 'question' => '¿Cuánto es el subsidio por lactancia y cómo lo cobro?', 'answer' => 'El monto es de S/ 820.00 por cada hijo nacido vivo. Lo cobras de dos maneras: si diste a luz en un hospital de EsSalud, el pago es automático (\"Cero Trámite\") y te depositan sin que hagas nada. Si fue en clínica particular, tú tienes que presentar el Formulario 1040 en EsSalud o por la plataforma VIVA, y luego te pagan.', 'keywords' => '["monto", "subsidio", "lactancia", "cuánto", "cobro", "importe"]'],
            ['category_name' => 'Subsidio por Lactancia', 'question' => '¿Cómo sé si mi subsidio por lactancia será por el sistema \"Cero Trámite\"?', 'answer' => 'Es muy fácil: si tu parto fue en un hospital o clínica de EsSalud, ellos mismos registran el nacimiento en su sistema y el subsidio se activa solo, sin que tengas que hacer ningún trámite. Si tu parto fue en una clínica particular que no es de EsSalud, entonces sí tienes que hacer el trámite tú misma.', 'keywords' => '["cómo", "subsidio", "lactancia", "será", "sistema", "cero", "trámite"]'],
            ['category_name' => 'Subsidio por Lactancia', 'question' => '¿Cómo funciona el pago de lactancia \"Cero Trámites\" si doy a luz en un hospital de EsSalud?', 'answer' => 'Es automático. Cuando das a luz en un hospital de EsSalud, ellos registran el nacimiento en su sistema. Esa información llega al área de prestaciones económicas y activan el pago sin que tú hagas nada. En unos días te depositan los S/ 820 in el banco o te avisan que pases a cobrar.', 'keywords' => '["cómo", "funciona", "pago", "lactancia", "cero", "trámites", "hospital", "essalud"]'],
            ['category_name' => 'Subsidio por Lactancia', 'question' => '¿Qué hago si mi parto fue en una clínica particular, puedo recibir el subsidio por lactancia?', 'answer' => 'Sí, claro que sí. No importa dónde hayas dado a luz, el derecho al subsidio es tuyo. Lo que cambia es que tú tienes que hacer el trámite. Debes presentar el Formulario 1040, el acta de nacimiento de tu bebé, tu DNI y el certificado de nacido vivo. Lo haces en la plataforma VIVA o en una oficina de EsSalud.', 'keywords' => '["hago", "parto", "clínica", "particular", "recibir", "subsidio", "lactancia"]'],
            ['category_name' => 'Subsidio por Lactancia', 'question' => '¿Necesito presentar algún formulario en el banco para cobrar el subsidio por lactancia?', 'answer' => 'No, en el banco no te piden ningún formulario. El banco solo te pide tu DNI y, si tienes una cuenta a tu nombre, te depositan allí. Si no tienes cuenta, te dan el dinero en ventanilla con tu DNI. Todo el papeleo se hace antes, en EsSalud o en VIVA.', 'keywords' => '["presentar", "algún", "formulario", "banco", "cobrar", "subsidio", "lactancia"]'],
            ['category_name' => 'Subsidio por Lactancia', 'question' => '¿Cómo sé si mi trámite de lactancia ya fue evaluado?', 'answer' => 'Puedes verificarlo en VIVA o en la web de consultas de subsidios colocando tu DNI. Si el estado cambia a \"Aprobado\" o \"Listo para pago\", significa que ya se emitió la orden de pago para que cobres el beneficio económico de S/. 820\.', 'keywords' => '["cómo", "trámite", "lactancia", "evaluado"]'],
            ['category_name' => 'Subsidio por Lactancia', 'question' => '¿Tuve mellizos, recibo un solo subsidio de lactancia?', 'answer' => '¡Felicidades\! Y no, recibes un subsidio por cada hijo. Si tuviste mellizos, son dos pagos de S/ 820 cada uno (S/ 1,640 en total). Si fueron trillizos, serían tres pagos. Así que sí, el subsidio es por cada recién nacido vivo.', 'keywords' => '["tuve", "mellizos", "recibo", "solo", "subsidio", "lactancia"]'],
            ['category_name' => 'Subsidio por Lactancia', 'question' => '¿Puedo pedir el subsidio de lactancia si el bebé falleció poco después de nacer?', 'answer' => 'Sí, igual lo recibes. El subsidio de lactancia es por el nacimiento vivo, no porque el bebé siga vivo después. Si tu bebé nació vivo (aunque haya fallecido días después), tienes derecho al subsidio de S/ 820\. Solo necesitas el acta de nacimiento y, si falleció, también el acta de defunción.', 'keywords' => '["pedir", "subsidio", "lactancia", "bebé", "falleció", "poco", "después", "nacer"]'],
            ['category_name' => 'Subsidio por Lactancia', 'question' => '¿Quién debe cobrar el subsidio de lactancia si la madre es menor de edad y soltera?', 'answer' => 'Si la madre es menor de edad y soltera, el subsidio lo puede cobrar su padre, madre o tutor del bebé (los abuelos o el adulto responsable). Ellos deben presentar su DNI y acreditar que tienen al bebé a su cargo.', 'keywords' => '["quién", "debe", "cobrar", "subsidio", "lactancia", "madre", "menor", "edad"]'],
            ['category_name' => 'Subsidio por Lactancia', 'question' => '¿Cuánto tiempo tengo para cobrar mi subsidio de lactancia?', 'answer' => 'Tienes 6 meses desde que terminó tu descanso post parto. Es decir, si tu bebé nació el 1 de enero y tu descanso terminó el 31 de marzo, tienes hasta el 30 de septiembre para cobrar.', 'keywords' => '["cuánto", "tiempo", "cobrar", "subsidio", "lactancia"]'],
            ['category_name' => 'Subsidio por Maternidad', 'question' => '¿Cuáles son los requisitos para solicitar el subsidio por maternidad?', 'answer' => 'Necesitas cumplir con tres cosas: 1\) Haber estado afiliada a EsSalud en el momento que quedaste embarazada (desde la concepción). 2\) Tener 3 meses de aportes seguidos o 4 no seguidos en los últimos 6 meses antes de tu descanso. 3\) Tener vínculo laboral activo al momento del parto (o estar en tu período de latencia si te despidieron).', 'keywords' => '["cuáles", "requisitos", "solicitar", "subsidio", "maternidad"]'],
            ['category_name' => 'Subsidio por Maternidad', 'question' => '¿Cuánto tiempo tengo para solicitar el subsidio por maternidad?', 'answer' => 'Tienes 6 meses desde que termina tu descanso post parto (los 90 días o 98 días). Por ejemplo, si tu bebé nació el 1 de enero y tu descanso terminó el 31 de marzo, tienes hasta el 30 de septiembre para pedir tu subsidio. Si pasas ese tiempo, pierdes el derecho.', 'keywords' => '["cuánto", "tiempo", "solicitar", "subsidio", "maternidad"]'],
            ['category_name' => 'Subsidio por Maternidad', 'question' => '¿Cómo se paga el subsidio por maternidad?', 'answer' => 'Depende de tu tipo de trabajo. Si eres trabajadora dependiente (tienes empleador), él te paga el subsidio en tu misma fecha de pago de sueldo, y después él le pide a EsSalud que le devuelva la plata. Si eres independiente (trabajadora del hogar, pescadora, agraria independiente), EsSalud te paga directamente en tu cuenta o en ventanilla del banco.', 'keywords' => '["cómo", "paga", "subsidio", "maternidad"]'],
            ['category_name' => 'Subsidio por Maternidad', 'question' => '¿Puedo pedir mi subsidio de maternidad antes de que termine mi descanso?', 'answer' => 'Sí, puedes. No tienes que esperar a que se termine tu licencia de 90 o 98 días. Puedes presentar tu solicitud antes, pero el pago se empieza a contar desde que empezó tu descanso. Es mejor presentarlo apenas tengas todos los papeles para no olvidarte.', 'keywords' => '["pedir", "subsidio", "maternidad", "antes", "termine", "descanso"]'],
            ['category_name' => 'Subsidio por Maternidad', 'question' => '¿Cuál es el plazo máximo para solicitar el reembolso por maternidad?', 'answer' => 'El empleador tiene 6 meses desde que terminó el período de descanso de la trabajadora (los 90 o 98 días) para pedir el reembolso a EsSalud. Si pasa ese tiempo, pierde el derecho a que le devuelvan la plata.', 'keywords' => '["cuál", "plazo", "máximo", "solicitar", "reembolso", "maternidad"]'],
            ['category_name' => 'Prestaciones Económicas', 'question' => '¿Qué es exactamente el subsidio por ITT?', 'answer' => 'ITT significa \"Incapacidad Temporal para el Trabajo\". Es el dinero que recibes cuando te enfermas o te accidentas (si no es por trabajo) y no puedes ir a trabajar por varios días. Es como un \"seguro de salud\" que te paga un sueldo mientras te recuperas, para que no te quedes sin ingresos.', 'keywords' => '["exactamente", "subsidio"]'],
            ['category_name' => 'Prestaciones Económicas', 'question' => '¿Cómo solicito el subsidio por incapacidad temporal?', 'answer' => 'Primero, tu médico te da un Certificado de Incapacidad Temporal (CITT). Si el médico es de EsSalud, el certificado ya está listo. Si es un médico particular, primero debes validar ese certificado en el CITT o en la plataforma VIVA. Luego, llenas el Formulario 1040 y lo presentas en EsSalud (por VIVA o presencial). Si eres trabajador dependiente, tu empleador puede hacer el trámite de reembolso.', 'keywords' => '["cómo", "solicito", "subsidio", "incapacidad", "temporal"]'],
            ['category_name' => 'Prestaciones Económicas', 'question' => '¿Cuándo empieza a pagar EsSalud el subsidio por incapacidad temporal? / ¿A partir de qué día EsSalud asume el pago?', 'answer' => 'EsSalud empieza a pagar recién a partir del día 21 de tu incapacidad. Los primeros 20 días los paga tu empleador (con tu sueldo normal). Si tu enfermedad se alarga más de 20 días, EsSalud te cubre desde el día 21 en adelante.', 'keywords' => '["cuándo", "empieza", "pagar", "essalud", "subsidio", "incapacidad", "temporal", "partir"]'],
            ['category_name' => 'Prestaciones Económicas', 'question' => '¿Cuánto dura el subsidio por incapacidad temporal como máximo?', 'answer' => 'El tiempo máximo que puedes recibir este subsidio por una misma enfermedad o accidente es de 11 meses y 10 días seguidos. Si después de ese tiempo aún no te recuperas, un comité médico evalúa si tu incapacidad ya es permanente o si necesitas más tiempo.', 'keywords' => '["cuánto", "dura", "subsidio", "incapacidad", "temporal", "máximo"]'],
            ['category_name' => 'Prestaciones Económicas', 'question' => '¿Qué pasa si presento mi solicitud de subsidio después de los 6 meses? / ¿Cuál es el último día que tengo para presentar mi solicitud de pago?', 'answer' => 'Si presentas tu solicitud después de los 6 meses desde que terminó tu incapacidad, pierdes el derecho al subsidio. EsSalud ya no te va a pagar. Tienes 6 meses desde que terminó tu incapacidad. Por ejemplo, si te recuperaste el 31 de marzo, tienes hasta el 30 de septiembre para presentar tu solicitud.', 'keywords' => '["pasa", "presento", "solicitud", "subsidio", "después", "meses", "cuál", "último"]'],
            ['category_name' => 'Prestaciones Económicas', 'question' => '¿Qué plazo tiene el empleador o asegurado para solicitar el reembolso de una incapacidad temporal?', 'answer' => 'Tienen 6 meses desde que terminó la incapacidad para presentar la solicitud de reembolso.', 'keywords' => '["plazo", "empleador", "asegurado", "solicitar", "reembolso", "incapacidad", "temporal"]'],
            ['category_name' => 'Prestaciones Económicas', 'question' => '¿Quién es el responsable de tramitar el subsidio de una trabajadora del hogar?', 'answer' => 'La propia trabajadora del hogar. Ella debe hacer el trámite directamente en EsSalud (pago directo). Su empleador no está obligado a hacer el reembolso para este caso.', 'keywords' => '["quién", "responsable", "tramitar", "subsidio", "trabajadora", "hogar"]'],
            ['category_name' => 'Prestaciones Económicas', 'question' => '¿Cuál es la obligación del empleador respecto al pago del subsidio para un trabajador dependiente?', 'answer' => 'El empleador tiene que pagar los primeros 20 días de incapacidad. Además, si el trabajador sigue enfermo, el empleador tiene que seguir pagando el subsidio por cuenta de EsSalud (y luego pedir el reembolso). También debe declarar correctamente los días trabajados y las incapacidades en la planilla electrónica.', 'keywords' => '["cuál", "obligación", "empleador", "respecto", "pago", "subsidio", "trabajador", "dependiente"]'],
            ['category_name' => 'Prestaciones Económicas', 'question' => '¿Qué grupos de trabajadores reciben el pago SIEMPRE de forma directa por EsSalud?', 'answer' => 'Son los trabajadores del hogar, los trabajadores de construcción civil, los trabajadores de Unidades Ejecutoras del Presupuesto del Sector Público, los pescadores artesanales independientes y los agrarios independientes. Para ellos, EsSalud les paga directamente, sin pasar por un empleador.', 'keywords' => '["grupos", "trabajadores", "reciben", "pago", "siempre", "forma", "directa", "essalud"]'],
            ['category_name' => 'Subsidio por Sepelio', 'question' => '¿Cómo solicito el reembolso por sepelio y cuál es el monto máximo?', 'answer' => 'Llenas el Formulario 1040 (sección de sepelio), adjuntas el acta de defunción de tu familiar, los comprobantes de gastos funerarios (facturas o boletas) a tu nombre, y tu DNI. Lo presentas en EsSalud (VIVA o presencial). El monto máximo que te reembolsan es S/ 2,070.', 'keywords' => '["cómo", "solicito", "reembolso", "sepelio", "cuál", "monto", "máximo"]'],
            ['category_name' => 'Subsidio por Sepelio', 'question' => '¿Qué gastos funerarios cubre la prestación por sepelio? / ¿Qué gastos cubre exactamente?', 'answer' => 'Cubren los gastos básicos y necesarios para un entierro digno: el ataúd, el nicho o la sepultura, la cremación si la eliges, la capilla ardiente, la carroza fúnebre, el transporte del cuerpo, la mortaja y la preparación del cadáver. No cubren flores, esquelas, lápidas lujosas ni gastos de lujo o servicios adicionales que no sean indispensables.', 'keywords' => '["gastos", "funerarios", "cubre", "prestación", "sepelio", "gastos", "cubre", "exactamente"]'],
            ['category_name' => 'Subsidio por Sepelio', 'question' => '¿Cuál es el plazo máximo para solicitar el subsidio por sepelio?', 'answer' => 'Tienes 6 meses desde la fecha del fallecimiento de tu familiar. Si pasas ese tiempo, pierdes el derecho al reembolso.', 'keywords' => '["cuál", "plazo", "máximo", "solicitar", "subsidio", "sepelio"]'],
            ['category_name' => 'Subsidio por Sepelio', 'question' => '¿Quiénes tienen derecho a cobrar el subsidio por sepelio? / ¿Quién tiene el derecho preferente?', 'answer' => 'El dinero se paga en este orden de preferencia: primero al cónyuge o concubino del fallecido. Si no hay, a los hijos. Si no hay hijos, a los padres. Si no hay padres, a los hermanos. Y si no hay ninguno de ellos, a cualquier tercero que demuestre con facturas reales que él pagó el entierro.', 'keywords' => '["quiénes", "tienen", "derecho", "cobrar", "subsidio", "sepelio", "quién", "derecho"]'],
            ['category_name' => 'Subsidio por Sepelio', 'question' => '¿Cuáles son los montos fijos establecidos por el decreto para lactancia y sepelio?', 'answer' => 'Lactancia: S/ 820\. Sepelio: hasta S/ 2,070 (tope máximo de reembolso de gastos reales).', 'keywords' => '["cuáles", "montos", "fijos", "establecidos", "decreto", "lactancia", "sepelio"]'],
            ['category_name' => 'Subsidio por Sepelio', 'question' => '¿Qué información de las boletas de la funeraria debo ingresar al sistema o presentar?', 'answer' => 'No necesitas ingresar datos de una “boleta” en un sistema digital para el trámite de sepelio, generalmente se presenta la documentación física o escaneada. Los comprobantes válidos son originales. La información clave que deben contener es: el nombre del beneficiario (la persona que pagó y solicita el reembolso) y el detalle de los servicios básicos. Normalmente se aceptan comprobantes de nicho, sepultura, cremación, ataúd y carroza. Para otros gastos como capilla o preparación del cadáver, a veces se permite presentar una Declaración Jurada si no tienes la factura.', 'keywords' => '["información", "boletas", "funeraria", "debo", "ingresar", "sistema", "presentar"]'],
            ['category_name' => 'Subsidio por Sepelio', 'question' => '¿Qué tipos de comprobantes son válidos para solicitar el reembolso por gastos de sepelio?', 'answer' => 'Son válidos los comprobantes de pago originales (facturas o boletas) que estén emitidos a nombre del beneficiario que está solicitando el reembolso. Esto incluye compras de ataúd, nicho o cremación, carroza fúnebre y servicios de capilla. Si hiciste algún pago en efectivo y no te dieron factura, puedes presentar una Declaración Jurada de Gastos para complementar.', 'keywords' => '["tipos", "comprobantes", "válidos", "solicitar", "reembolso", "gastos", "sepelio"]'],
            ['category_name' => 'Prestaciones Económicas', 'question' => '¿Qué hago si fui al banco a cobrar mi subsidio y me dicen que el depósito no está disponible?', 'answer' => 'Pueden pasar dos cosas. Una: aún no ha llegado la orden de pago al banco (espera 2 o 3 días más). Dos: el dinero ya regresó a EsSalud porque pasaron más de 20 días hábiles desde que se generó el pago. Si es lo segundo, tienes que pedir la rehabilitación de pago en EsSalud.', 'keywords' => '["hago", "banco", "cobrar", "subsidio", "dicen", "depósito", "está", "disponible"]'],
            ['category_name' => 'Prestaciones Económicas', 'question' => '¿Cuántos días tengo para cobrar un subsidio en el banco antes de que el dinero regrese a EsSalud?', 'answer' => 'Tienes 20 días hábiles contados desde la fecha en que se generó el pago (cuando el sistema marcó \"Conforme\"). Si no cobras dentro de ese plazo, el dinero retorna automáticamente a EsSalud y tendrás que hacer el trámite de rehabilitación de pago.', 'keywords' => '["cuántos", "días", "cobrar", "subsidio", "banco", "antes", "dinero", "regrese"]'],
            ['category_name' => 'Prestaciones Económicas', 'question' => '¿Qué hago si dejé pasar el plazo para cobrar mi subsidio? / Fui a cobrar al banco y me dijeron que el dinero regresó a EsSalud, ¿qué debo hacer?', 'answer' => 'No te preocupes, el dinero no se pierde. Lo que debes hacer ahora es ir a una oficina de EsSalud (OSPE) con tu DNI y pedir la Rehabilitación de Pago. Es un trámite administrativo para que te habiliten nuevamente el depósito o el pago en ventanilla. En unos días hábiles vuelven a habilitar el pago y puedes ir al banco. Cuando el estado del trámite cambia a \"Conforme\", significa que ya está aprobado, pero puede tardar unos días en generarse la orden de pago en el sistema bancario. Lo más seguro es esperar de 2 a 3 días hábiles después de ver el estado \"Conforme\" para ir al banco, así te aseguras de que el dinero esté disponible y evitas una vuelta en vano.', 'keywords' => '["hago", "dejé", "pasar", "plazo", "cobrar", "subsidio", "cobrar", "banco"]'],
            ['category_name' => 'Prestaciones Económicas', 'question' => '¿Qué trámite debo realizar si olvidé cobrar mi subsidio de EsSalud en la fecha programada?', 'answer' => 'Tienes que ir a una oficina de EsSalud (OSPE) con tu DNI y pedir la Rehabilitación de Pago. Te van a pedir el número de expediente (si lo tienes, mejor). Activarán el pago nuevamente y podrás ir al banco en unos días hábiles. No es un trámite complicado, pero sí es presencial.', 'keywords' => '["trámite", "debo", "realizar", "olvidé", "cobrar", "subsidio", "essalud", "fecha"]'],
            ['category_name' => 'Prestaciones Económicas', 'question' => '¿Quiénes están autorizados para solicitar la reactivación de un pago de subsidio no cobrado?', 'answer' => 'Si el subsidio es del titular con vida, solo el titular puede pedir la rehabilitación. Si el titular falleció, pueden pedirla sus herederos con la documentación que acredite que son los beneficiarios (testamento, sucesión intestada o declaración jurada según el monto).', 'keywords' => '["quiénes", "están", "autorizados", "solicitar", "reactivación", "pago", "subsidio", "cobrado"]'],
            ['category_name' => 'Prestaciones Económicas', 'question' => '¿Necesito saber mi número de expediente para reactivar el pago automático de mi subsidio por lactancia?', 'answer' => 'No es obligatorio, pero sí ayuda muchísimo. Si tienes tu número de expediente, el trámite es mucho más rápido. Si no lo tienes, el personal de EsSalud puede buscarte con tu DNI. Igual es buena idea que anotes ese número cuando te den la resolución de aprobación.', 'keywords' => '["número", "expediente", "reactivar", "pago", "automático", "subsidio", "lactancia"]'],
            ['category_name' => 'Prestaciones Económicas', 'question' => '¿Qué sucede si un tercero va a realizar el trámite de ITT en mi nombre?', 'answer' => 'Esa persona debe llevar su DNI y una carta poder simple firmada por ti donde autorizas a \"Fulano\" a hacer el trámite. Si el monto del subsidio es alto (más de 3 UIT), se necesita poder notarial.', 'keywords' => '["sucede", "tercero", "realizar", "trámite", "nombre"]'],
            ['category_name' => 'Prestaciones Económicas', 'question' => '¿Qué pasa si el titular del subsidio falleció y EsSalud aún no ha realizado el pago directo? / Mi familiar falleció y tenía un subsidio aprobado pendiente de cobro, ¿qué documentos debo presentar como heredero según el monto?', 'answer' => 'Los herederos pueden cobrar ese dinero. Depende de cuánto dinero esté pendiente. Si el monto es menor o igual a la media UIT (actualmente S/ 2,750), basta una Declaración Jurada de Herederos con firma y huella digital. Si es más de S/ 2,750 y hasta 3 UIT (S/ 16,500), necesitarás un Testamento o Sucesión Intestada que acredite quiénes son los herederos, más un poder simple a favor de uno de ellos para que cobre por todos. Si pasa las 3 UIT, necesitas Poder por Escritura Pública.', 'keywords' => '["pasa", "titular", "subsidio", "falleció", "essalud", "realizado", "pago", "directo"]'],
            ['category_name' => 'Prestaciones Económicas', 'question' => '¿Qué tipo de poder necesito según el monto del subsidio de un fallecido?', 'answer' => 'Si el monto es menor o igual a media UIT (S/ 2,750), basta una Declaración Jurada de Herederos con firma y huella. Si es más de S/ 2,750 y hasta 3 UIT (S/ 16,500), necesitas testamento o sucesión intestada más un poder simple. Si es más de 3 UIT, necesitas poder por escritura pública.', 'keywords' => '["tipo", "poder", "según", "monto", "subsidio", "fallecido"]'],
            ['category_name' => 'Prestaciones Económicas', 'question' => '¿En qué situaciones puedo perder el derecho a seguir cobrando el subsidio?', 'answer' => 'Pierdes el derecho si: 1\) Te despiden o pierdes tu trabajo, 2\) Te recuperas y ya no estás enfermo, 3\) El comité médico dice que tu incapacidad ya es permanente (ya no es temporal), 4\) Trabajas mientras cobras el subsidio, 5\) Abandonas el tratamiento médico sin justificación.', 'keywords' => '["situaciones", "perder", "derecho", "seguir", "cobrando", "subsidio"]'],
            ['category_name' => 'Prestaciones Económicas', 'question' => '¿Cuánto tiempo se otorga para la devolución voluntaria de un pago indebido detectado por EsSalud?', 'answer' => 'Si EsSalud detecta que te pagaron de más o que no te correspondía el subsidio, te notifica y te da 3 días hábiles para que devuelvas el dinero voluntariamente. Si no lo haces, inician el proceso de cobranza legal.', 'keywords' => '["cuánto", "tiempo", "otorga", "devolución", "voluntaria", "pago", "indebido", "detectado"]'],
            ['category_name' => 'Consultas Generales', 'question' => '¿Qué norma aprobó el actual TUPA de EsSalud y quién la firmó? / ¿Qué norma aprobó el TUPA vigente y cuál es su impacto?', 'answer' => 'El Texto Único de Procedimientos Administrativos (TUPA) de EsSalud se aprueba mediante un Decreto Supremo del Estado. Al ser una norma de este rango, lleva la firma del Presidente de la República y de los ministros de los sectores involucrados (como Trabajo y Promoción del Empleo, Economía y Finanzas). Su impacto directo es positivo para ti: reduce las trabas de papel, prohíbe que te exijan documentos que la propia entidad ya tiene en sus bases de datos y agiliza los tiempos de respuesta.', 'keywords' => '["norma", "aprobó", "actual", "tupa", "essalud", "quién", "firmó", "norma"]'],
            ['category_name' => 'Consultas Generales', 'question' => '¿Cuál es la finalidad principal de EsSalud según su ley de creación?', 'answer' => 'La finalidad principal es dar cobertura a los asegurados y sus familias mediante prestaciones de salud, económicas (subsidios) y sociales. Su objetivo es protegerlos frente a riesgos de enfermedad, maternidad, invalidez o fallecimiento, garantizando el bienestar de los trabajadores.', 'keywords' => '["cuál", "finalidad", "principal", "essalud", "según", "creación"]'],
            ['category_name' => 'Consultas Generales', 'question' => '¿Qué es el Sistema Único de Trámites (SUT) y para qué sirve?', 'answer' => 'Es una herramienta informática creada por el Estado peruano para que todas las entidades públicas registren, simplifiquen y estandaricen sus trámites. Sirve para evitar que te pidan requisitos inútiles y para hacer que los procesos sean más rápidos y transparentes para el ciudadano.', 'keywords' => '["sistema", "único", "trámites", "sirve"]'],
            ['category_name' => 'Consultas Generales', 'question' => '¿Qué sucede con los TUPA anteriores una vez que se publica el nuevo Decreto Supremo?', 'answer' => 'Los TUPA anteriores quedan automáticamente derogados (dejan de tener validez). Desde el día siguiente de la publicación del nuevo Decreto Supremo, la institución está obligada a aplicar únicamente las reglas y requisitos que aparecen en la nueva versión.', 'keywords' => '["sucede", "tupa", "anteriores", "publica", "nuevo", "decreto", "supremo"]'],
            ['category_name' => 'Consultas Generales', 'question' => '¿Por qué EsSalud debe actualizar su TUPA periódicamente?', 'answer' => 'Debe hacerlo para adaptarse a las nuevas leyes de simplificación administrativa, eliminar requisitos duplicados y digitalizar trámites. El objetivo es que hacer una solicitud te resulte cada vez más fácil y requiera menos papeles.', 'keywords' => '["essalud", "debe", "actualizar", "tupa", "periódicamente"]'],
            ['category_name' => 'Consultas Generales', 'question' => '¿Qué debe contener obligatoriamente cada procedimiento en el TUPA?', 'answer' => 'Cada trámite debe detallar de forma obligatoria: el nombre del procedimiento, los requisitos exactos que debes presentar, si tiene algún costo (tasa), cuánto tiempo máximo tiene la entidad para responder, qué oficina resuelve el trámite y qué recurso puedes presentar si te lo rechazan.', 'keywords' => '["debe", "contener", "obligatoriamente", "cada", "procedimiento", "tupa"]'],
            ['category_name' => 'Consultas Generales', 'question' => '¿Dónde se debe publicar oficialmente el TUPA para que sea válido?', 'answer' => 'Debe publicarse oficialmente en el Diario Oficial El Peruano y, además, difundirse en el Portal de Servicios al Ciudadano y en la página web oficial de la institución para que cualquier persona pueda revisarlo de forma transparente.', 'keywords' => '["dónde", "debe", "publicar", "oficialmente", "tupa", "válido"]'],
            ['category_name' => 'Consultas Generales', 'question' => '¿Quiénes fijan el monto de las tasas o derechos de tramitación?', 'answer' => 'Los montos los calcula el área de administración y costos de la propia institución siguiendo metodologías oficiales impuestas por la Presidencia del Consejo de Ministros (PCM), y se aprueban formalmente dentro del mismo Decreto Supremo del TUPA.', 'keywords' => '["quiénes", "fijan", "monto", "tasas", "derechos", "tramitación"]'],
            ['category_name' => 'Consultas Generales', 'question' => '¿Qué es un \"Servicio Prestado en Exclusividad\" según el documento?', 'answer' => 'Es un servicio que solo y únicamente te puede brindar esa entidad pública, ya que ninguna empresa privada tiene la facultad legal para hacerlo (por ejemplo, la validación oficial de un descanso médico particular para emitir un certificado CITT).', 'keywords' => '["servicio", "prestado", "exclusividad", "según", "documento"]'],
            ['category_name' => 'Consultas Generales', 'question' => '¿Bajo qué resolución se aprueban los trámites actuales de subsidios en EsSalud?', 'answer' => 'Los flujos administrativos internos se regulan mediante Resoluciones de Gerencia General de EsSalud, las cuales se diseñan respetando la Ley de Modernización de la Seguridad Social en Salud (Ley N° 26790\) y sus reglamentos vigentes.', 'keywords' => '["bajo", "resolución", "aprueban", "trámites", "actuales", "subsidios", "essalud"]'],
            ['category_name' => 'Consultas Generales', 'question' => '¿Qué leyes respaldan el pago de prestaciones económicas como maternidad o sepelio?', 'answer' => 'Están respaldadas por la Ley N° 26790 (Ley de Modernización de la Seguridad Social en Salud) y su reglamento (Decreto Supremo N° 009-97-SA). También existen seguros complementarios obligatorios como la Ley de Consolidación de Beneficios Sociales (D.L. 688\) para el Seguro Vida Ley.', 'keywords' => '["leyes", "respaldan", "pago", "prestaciones", "económicas", "maternidad", "sepelio"]'],
            ['category_name' => 'Consultas Generales', 'question' => '¿Qué es el silencio administrativo negativo en mi solicitud de subsidio? / ¿Qué ocurre si EsSalud no responde dentro del plazo legal de 15 días?', 'answer' => 'Significa que si EsSalud supera el plazo máximo legal de 15 días hábiles para responder a tu solicitud y no se ha pronunciado, debes considerar que tu pedido ha sido denegado (\"rechazado\") por silencio administrativo negativo. Esto no significa que te vayan a pagar, sino que te da el derecho legal de presentar un recurso de apelación para que revisen tu caso.', 'keywords' => '["silencio", "administrativo", "negativo", "solicitud", "subsidio", "ocurre", "essalud", "responde"]'],
            ['category_name' => 'Consultas Generales', 'question' => '¿Qué es la cláusula de protección de datos personales and por qué debo aceptarla?', 'answer' => 'Es un texto legal donde autorizas a EsSalud a guardar y usar tus datos (nombre, DNI, historial médico) de forma confidencial. Debes aceptarla porque la ley exige tu consentimiento explícito para que el sistema informático pueda procesar tus trámites y consultas de salud de forma segura.', 'keywords' => '["cláusula", "protección", "datos", "personales", "debo", "aceptarla"]'],
            ['category_name' => 'Consultas Generales', 'question' => '¿Es seguro aceptar el tratamiento de mis datos personales en las plataformas de EsSalud?', 'answer' => 'Sí, totalmente seguro. Las plataformas públicas están obligadas por ley a cumplir con estrictas medidas de seguridad informática para evitar que tu información médica o personal sea robada o compartida con terceros sin tu autorización.', 'keywords' => '["seguro", "aceptar", "tratamiento", "datos", "personales", "plataformas", "essalud"]'],
            ['category_name' => 'Consultas Generales', 'question' => '¿Cómo puedo ejercer mis derechos ARCO (acceso, rectificación, cancelación y oposición)?', 'answer' => 'Puedes ejercerlos presentando una solicitud formal (física o digital) ante la institución. Tienes derecho a pedir que te muestren qué datos tuyos tienen (Acceso), que corrijan un error (Rectificación), que eliminen información si ya no es necesaria (Cancelación) o negarte a un uso específico (Oposición).', 'keywords' => '["cómo", "ejercer", "derechos", "arco", "acceso", "rectificación", "cancelación", "oposición"]'],
            ['category_name' => 'Consultas Generales', 'question' => '¿Qué es la Tabla de Clasificación Internacional Uniforme de Ocupaciones (CIUO) en el proceso?', 'answer' => 'Es un sistema de códigos internacionales que sirve para clasificar de manera idéntica los puestos de trabajo en todo el mundo. EsSalud lo utiliza (en el Anexo 10, por ejemplo) para saber exactamente qué tareas físicas o de riesgo realizas habitualmente en tu puesto laboral.', 'keywords' => '["tabla", "clasificación", "internacional", "uniforme", "ocupaciones", "ciuo", "proceso"]'],
            ['category_name' => 'Consultas Generales', 'question' => '¿Qué sucede si EsSalud detecta que trabajé mientras estaba con descanso médico?', 'answer' => 'Si el sistema o una fiscalización detecta que realizaste labores remuneradas durante tu periodo de descanso, el derecho al subsidio por incapacidad temporal se extingue o se pierde por completo. Además, te expones a sanciones legales.', 'keywords' => '["sucede", "essalud", "detecta", "trabajé", "mientras", "estaba", "descanso", "médico"]'],
            ['category_name' => 'Consultas Generales', 'question' => '¿Cuál es la multa por falsificar documentos para obtener un subsidio?', 'answer' => 'No solo te quitan el beneficio económico y te obligan a devolver todo el dinero robado más los intereses (resarcir daños), sino que EsSalud te denunciará penalmente ante el Ministerio Público, exponiéndote a penas de cárcel por el delito de fraude y falsificación de documentos públicos.', 'keywords' => '["cuál", "multa", "falsificar", "documentos", "obtener", "subsidio"]'],
            ['category_name' => 'Consultas Generales', 'question' => '¿Qué multas existen si mi empresa no entrega los libros o documentos a EsSalud?', 'answer' => 'Las empresas que se niegan a entregar información o planillas durante una auditoría o fiscalización posterior son sancionadas con multas económicas severas impuestas por las entidades reguladoras laborales (como Sunafil o el propio EsSalud), calculadas según el tamaño de la empresa y la gravedad de la falta.', 'keywords' => '["multas", "existen", "empresa", "entrega", "libros", "documentos", "essalud"]'],
            ['category_name' => 'Consultas Generales', 'question' => '¿Qué se considera “información no conforme con la realidad”?', 'answer' => 'Es cualquier dato, declaración o papel presentado que sea falso, esté adulterado o haya sido \"inflado\" deliberadamente (por ejemplo, declarar un sueldo falso para cobrar un subsidio más alto o inventar días de descanso médico).', 'keywords' => '["considera", "información", "conforme", "realidad"]'],
            ['category_name' => 'Consultas Generales', 'question' => '¿Qué hago si mi empleador declaró en planilla que trabajé durante mi licencia de maternidad?', 'answer' => 'Eso está mal hecho. Tu empleador no puede declarar días trabajados mientras tú estabas de descanso por maternidad. Si eso pasa, EsSalud puede rechazar tu subsidio. Lo que debes hacer es hablar con tu empleador para que corrija la planilla (presente una rectificación) y declare que esos días no trabajaste. Si no lo hace, ve a EsSalud con tus documentos y ellos te orientan.', 'keywords' => '["hago", "empleador", "declaró", "planilla", "trabajé", "durante", "licencia", "maternidad"]'],
            ['category_name' => 'Consultas Generales', 'question' => '¿Qué hago si mi empleador no me pagó los primeros 20 días de incapacidad?', 'answer' => 'Ahí tu empleador está incumpliendo la ley. Tú puedes reclamar. Primero, háblalo con él. Si no te resuelve, puedes pedir a EsSalud que te pague todo el subsidio desde el día 1, y luego EsSalud le cobrará a tu empleador. También puedes denunciar a tu empleador en SUNAFIL.', 'keywords' => '["hago", "empleador", "pagó", "primeros", "días", "incapacidad"]'],
            ['category_name' => 'Consultas Generales', 'question' => '¿Puede EsSalud descontar deudas de mi reembolso?', 'answer' => 'Sí. Si tu empresa tiene deudas exigibles con EsSalud (aportes impagos), EsSalud puede retener la totalidad o parte del monto del reembolso para pagar esas deudas. EsSalud le avisa a la empresa y aplica el descuento de oficio.', 'keywords' => '["puede", "essalud", "descontar", "deudas", "reembolso"]'],
            ['category_name' => 'Consultas Generales', 'question' => '¿Qué pasa si mi empresa no me paga el subsidio que le toca reembolsar?', 'answer' => 'Si la empresa recibe el reembolso de EsSalud pero no te paga a ti, tú puedes reclamar. EsSalud, al detectar que la empresa incumple, puede pagarte directamente a ti y luego cobrarle a la empresa. También puedes denunciar a la empresa en SUNAFIL.', 'keywords' => '["pasa", "empresa", "paga", "subsidio", "toca", "reembolsar"]'],
            ['category_name' => 'Consultas Generales', 'question' => '¿Cuál es el monto máximo que puede adeudar un empleador para no perder el derecho al reembolso?', 'answer' => 'Si el adeudo por mes no supera el 0.2% de la UIT y el total de adeudos no supera el 15% de la UIT, el empleador puede regularizar y no pierde el derecho al reembolso. Si pasa esos límites, sí pierde el derecho y EsSalud le cobra todo.', 'keywords' => '["cuál", "monto", "máximo", "puede", "adeudar", "empleador", "perder", "derecho"]'],
            ['category_name' => 'Consultas Generales', 'question' => '¿Qué sucede si los días de subsidio coinciden con días declarados como laborados en la planilla?', 'answer' => 'EsSalud te da 7 días hábiles para que subsanes (corrijas) la planilla o expliques la coincidencia. Si no lo haces, EsSalud solo te paga los días que no coinciden con días laborados.', 'keywords' => '["sucede", "días", "subsidio", "coinciden", "días", "declarados", "laborados", "planilla"]'],
            ['category_name' => 'Consultas Médicas', 'question' => '¿VIVA no reconoce mi certificado médico particular, qué debo hacer?', 'answer' => 'Los certificados médicos particulares no se cargan directo como un subsidio común; primero deben pasar por un proceso llamado Validación de Certificado Médico para que EsSalud emita un certificado oficial CITT. Debes ingresar a la opción de validación adjuntando el Formulario Anexo 10, tu informe médico, las recetas y las pruebas auxiliares (rayos X, análisis, etc.).', 'keywords' => '["viva", "reconoce", "certificado", "médico", "particular", "debo"]'],
            ['category_name' => 'Consultas Médicas', 'question' => '¿Qué es una cita por referencia y cómo funciona? / ¿Cómo saco una cita por referencia si mi centro no tiene la especialidad?', 'answer' => 'Es el proceso mediante el cual te derivan de tu policlínico básico hacia un hospital más grande porque necesitas exámenes especiales o la atención de un médico especialista (como un cardiólogo o neurólogo). El médico general de tu policlínico ingresa la solicitud en el sistema informático interno; el hospital de mayor complejidad revisa el caso y te asigna la cita. Puedes ver la programación en la app Mi Consulta.', 'keywords' => '["cita", "referencia", "cómo", "funciona", "cómo", "saco", "cita", "referencia"]'],
            ['category_name' => 'Consultas Médicas', 'question' => '¿Qué es una VDI y quién puede recibirla?', 'answer' => 'VDI significa Visita Domiciliaria Integral. Es una atención médica que brinda el equipo de salud directamente en la casa del paciente. Está diseñada exclusivamente para personas que no pueden moverse por sus propios medios, pacientes postrados, adultos mayores con enfermedades crónicas avanzadas o recién nacidos con alto riesgo detectado.', 'keywords' => '["quién", "puede", "recibirla"]'],
            ['category_name' => 'Consultas Médicas', 'question' => '¿Es obligatorio dejar entrar al equipo médico a mi casa?', 'answer' => 'No es una obligación legal por la fuerza, pero si estás afiliado a un programa de atención domiciliaria (como Padomi), es un requisito indispensable para recibir el beneficio médico. El personal debe ingresar para poder revisarte, ponerte tus medicamentos y verificar que te encuentres en un ambiente seguro y limpio.', 'keywords' => '["obligatorio", "dejar", "entrar", "equipo", "médico", "casa"]'],
            ['category_name' => 'Consultas Médicas', 'question' => '¿Qué evalúa el personal en mi domicilio además de mi salud?', 'answer' => 'Además de tu estado físico (presión, signos vitales), las enfermeras y médicos evalúan las condiciones del entorno: si tu habitación tiene buena ventilación y luz, si la higiene del cuarto es la adecuada, cómo guardan tus medicinas y si existen riesgos de caídas (cables sueltos, alfombras resbaladizas) para informarle a tu familia.', 'keywords' => '["evalúa", "personal", "domicilio", "además", "salud"]'],
            ['category_name' => 'Consultas Médicas', 'question' => '¿Qué pasa si una gestante adolescente falta a su cita programada?', 'answer' => 'Al considerarse un grupo de alta vulnerabilidad médica, el sistema de asistencia social activa de inmediato una alerta. El personal del policlínico se comunicará por teléfono con la menor o sus padres y, si es necesario, programará una Visita Domiciliaria (VDI) de urgencia para confirmar el estado de salud de la madre y del bebé.', 'keywords' => '["pasa", "gestante", "adolescente", "falta", "cita", "programada"]'],
            ['category_name' => 'Consultas Médicas', 'question' => '¿Qué validez tiene el informe IMECI si el resultado determina que la incapacidad es temporal?', 'answer' => 'Si el informe IMECI (Incapacidad Médica Evaluada por Comisión) dice que la incapacidad es temporal, ese informe tiene una validez de 6 meses. Durante ese tiempo, sigues recibiendo el subsidio según corresponda. Pasados los 6 meses, se necesita una nueva evaluación si la incapacidad continúa.', 'keywords' => '["validez", "informe", "imeci", "resultado", "determina", "incapacidad", "temporal"]'],
            ['category_name' => 'Consultas Generales', 'question' => '¿El seguro cubre mi tratamiento de ortodoncia (brackets)? / ¿El seguro cubre cirugías estéticas o brackets?', 'answer' => 'No, bajo ninguna modalidad o circunstancia. Quedan completamente excluidos de la cobertura del plan de salud básico y regular de EsSalud todos los tratamientos de ortodoncia (brackets) y las operaciones estéticas o plásticas orientadas únicamente a cambiar o mejorar la apariencia física del paciente.', 'keywords' => '["seguro", "cubre", "tratamiento", "ortodoncia", "brackets", "seguro", "cubre", "cirugías"]'],
            ['category_name' => 'Consultas Generales', 'question' => '¿Puedo pedir que me den lentes de contacto por el seguro?', 'answer' => 'No. El seguro de EsSalud no financia ni otorga lentes de contacto por motivos estéticos o de comodidad. Solo en hospitales especializados y para casos médicos de enfermedades de la córnea extremadamente graves y específicas (donde el lente sea parte del tratamiento reconstructivo de la visión) se evalúa su cobertura médica excepcional.', 'keywords' => '["pedir", "lentes", "contacto", "seguro"]'],
            ['category_name' => 'Consultas Generales', 'question' => '¿Me pueden hacer una cirugía plástica si no me gusta mi nariz?', 'answer' => 'No. Las cirugías estéticas o plásticas que se realizan con el único fin de mejorar la apariencia física personal o por gusto están totalmente excluidas del seguro. El seguro solo cubre cirugías reconstructivas en casos de accidentes graves, quemaduras o malformaciones congénitas severas.', 'keywords' => '["pueden", "cirugía", "plástica", "gusta", "nariz"]'],
            ['category_name' => 'Consultas Generales', 'question' => '¿Qué pasa si mi bebé nace con bajo peso?', 'answer' => 'El bebé es ingresado de inmediato al área de Neonatología o Cuidados Intensivos Neonatales (UCIN). Permanecerá en una incubadora especial bajo vigilancia médica las 24 horas del día, recibiendo soporte nutricional y clínico especializado hasta que logre alcanzar el peso y la madurez física óptima para ir a casa sano.', 'keywords' => '["pasa", "bebé", "nace", "bajo", "peso"]'],
            ['category_name' => 'Consultas Generales', 'question' => '¿Cuánto tiempo tiene EsSalud para darme los resultados de mi tamizaje de VPH o citología?', 'answer' => 'Los laboratorios de patología de los hospitales tienen un plazo promedio de 15 a 30 días calendario para emitir los resultados oficiales de las pruebas de Papanicolau o tamizajes de Virus del Papiloma Humano (VPH). Puedes monitorear si el resultado ya está listo ingresando a la aplicación Mi Consulta.', 'keywords' => '["cuánto", "tiempo", "essalud", "darme", "resultados", "tamizaje", "citología"]'],
            ['category_name' => 'Consultas Generales', 'question' => '¿Qué atención recibo si mi embarazo llega a las 41 semanas y no doy a luz?', 'answer' => 'Al considerarse un embarazo en vías de prolongación (lo cual genera un riesgo para el bebé), serás hospitalizada de inmediato en el área de ginecobstetricia. Los médicos evaluarán el estado del bebé y procederán a inducir el parto mediante medicamentos o programarán una cesárea de urgencia para proteger la vida de ambos.', 'keywords' => '["atención", "recibo", "embarazo", "llega", "semanas"]'],
            ['category_name' => 'Consultas Generales', 'question' => '¿Qué vacunas le deben poner a mi hijo apenas nazca?', 'answer' => 'Apenas nace el bebé (dentro de los primeros 28 días de vida) se le debe aplicar de forma obligatoria la vacuna BCG (que lo protege contra la tuberculosis pulmonar y meníngea) y la vacuna contra la Hepatitis B (dentro de las primeras 24 horas del nacimiento).', 'keywords' => '["vacunas", "deben", "poner", "hijo", "apenas", "nazca"]'],
            ['category_name' => 'Consultas Generales', 'question' => '¿Cuándo debo llevar a mi bebé a su primer control después de nacer?', 'answer' => 'Bajo el programa de Control de Niño Sano, debes programar tu primera evaluación pediátrica formal durante su primer mes de vida del recién nacido. Los controles durante todo su primer año deben realizarse de manera mensual para medir su crecimiento y desarrollo correcto.', 'keywords' => '["cuándo", "debo", "llevar", "bebé", "primer", "control", "después", "nacer"]'],
            ['category_name' => 'Consultas Generales', 'question' => '¿Qué atención recibo si tengo una deshidratación por diarrea?', 'answer' => 'Al considerarse una urgencia o potencial emergencia médica, serás ingresado de inmediato al área de atención de Emergencias del hospital asistencial. Recibirás de forma prioritaria rehidratación intravenosa (suero), medicamentos para controlar la infección y exámenes de laboratorio urgentes para estabilizarte. Ante cualquier sospecha o descarte de enfermedades oncológicas pediátricas, el sistema de EsSalud activa de inmediato protocolos médicos de prioridad absoluta. La referencia hacia el hospital especializado o de alta complejidad se procesa de forma directa e inmediata en pocas horas para que el niño sea evaluado sin demoras.', 'keywords' => '["atención", "recibo", "deshidratación", "diarrea"]'],
            ['category_name' => 'Consultas Generales', 'question' => '¿Qué es el tamizaje de salud mental y quién me lo debe realizar?', 'answer' => 'Es una evaluación breve basada en preguntas especializadas diseñada para detectar de forma temprana problemas como la depresión o ansiedad. Te lo debe realizar el personal de enfermería o el médico general durante tu consulta médica preventiva anual en tu policlínico.', 'keywords' => '["tamizaje", "salud", "mental", "quién", "debe", "realizar"]'],
            ['category_name' => 'Afiliaciones', 'question' => '¿Cuál es el periodo de carencia y cuánto dura?', 'answer' => 'Es el tiempo de espera obligatorio que debes cumplir al ingresar a un nuevo trabajo antes de poder pedir citas médicas comunes. Dura exactamente 3 meses desde el inicio de tu vínculo laboral.', 'keywords' => '["cuál", "periodo", "carencia", "cuánto", "dura"]'],
            ['category_name' => 'Afiliaciones', 'question' => '¿Puedo atenderme inmediatamente si acabo de conseguir trabajo?', 'answer' => 'Solo podrás atenderte de forma inmediata si sufres una emergencia médica por accidente, ya que ante un accidente el seguro te cubre desde el primer día de afiliación sin importar que estés en periodo de carencia. Para consultas comunes, debes esperar que pasen los 3 meses obligatorios.', 'keywords' => '["atenderme", "inmediatamente", "acabo", "conseguir", "trabajo"]'],
            ['category_name' => 'Afiliaciones', 'question' => '¿Qué pasa si mi empleador no ha pagado el seguro este mes, pierdo mi atención?', 'answer' => 'Como trabajador dependiente no pierdes tu atención de salud de forma inmediata si tienes aportes consecutivos anteriores acumulados. Sin embargo, EsSalud atenderá tu consulta y posteriormente le cobrará la totalidad de los gastos médicos a tu empresa morosa mediante una acción de cobranza, además de aplicarle multas. Sí, totalmente. La ley establece de forma obligatoria que todos los socios de cooperativas de trabajadores que laboran bajo relación de dependencia tienen la condición de afiliados regulares y deben contar con la cobertura completa de EsSalud.', 'keywords' => '["pasa", "empleador", "pagado", "seguro", "pierdo", "atención"]'],
            ['category_name' => 'Afiliaciones', 'question' => '¿Es cierto que si estoy embarazada no tengo que esperar los 3 meses de aportes?', 'answer' => 'No, las gestantes bajo el Seguro Regular común también deben cumplir con los criterios de aportación y vinculación vigentes para las prestaciones comunes. Recuerda que para acceder a los subsidios de dinero de maternidad, debes cumplir de forma estricta con contar con 3 meses de aportes consecutivos (o 4 no consecutivos) dentro de los 6 meses anteriores al descanso.', 'keywords' => '["cierto", "estoy", "embarazada", "esperar", "meses", "aportes"]'],
            ['category_name' => 'Afiliaciones', 'question' => '¿Me pueden descontar el 9% de mi sueldo para pagar el seguro?', 'answer' => 'No, está totalmente prohibido. La ley establece de manera clara que el aporte del 9% para EsSalud es de cargo directo y exclusivo de la empresa empleadora. Tu empleador debe pagarlo con su propio dinero; no te pueden quitar ni un solo sol de tu sueldo neto para este concepto.', 'keywords' => '["pueden", "descontar", "sueldo", "pagar", "seguro"]'],
            ['category_name' => 'Afiliaciones', 'question' => '¿Me han aplicado la Suspensión Perfecta de Labores, sigo teniendo seguro?', 'answer' => 'Sí, sigues teniendo cobertura de salud. La ley protege expresamente a los trabajadores afectados por una Suspensión Perfecta de Labores dándoles el derecho de acceder gratis a las prestaciones médicas de EsSalud a través del régimen especial de latencia durante el tiempo que dure la suspensión.', 'keywords' => '["aplicado", "suspensión", "perfecta", "labores", "sigo", "teniendo", "seguro"]'],
            ['category_name' => 'Afiliaciones', 'question' => '¿Cuántos meses de seguro gratis tengo si trabajé 2 años seguidos?', 'answer' => 'Si trabajaste 2 años seguidos sin parar, acumulaste exactamente 24 meses de aportaciones consecutivas. Revisando la tabla oficial de latencia, el periodo de aportes de 20 a 24 meses te otorga de forma exacta 8 meses de seguro médico totalmente gratis desde la fecha de tu cese laboral.', 'keywords' => '["cuántos", "meses", "seguro", "gratis", "trabajé", "años", "seguidos"]'],
            ['category_name' => 'Afiliaciones', 'question' => '¿Cómo tramito la cobertura por desempleo (latencia)?', 'answer' => 'Al quedarse sin empleo, la empresa procesa tu cese laboral en la planilla electrónica. El sistema informático de EsSalud calcula de forma automática tus meses de aporte y activa tu periodo de latencia correspondiente sin que tengas que hacer colas ni papeleos.', 'keywords' => '["cómo", "tramito", "cobertura", "desempleo", "latencia"]'],
            ['category_name' => 'Afiliaciones', 'question' => '¿Cómo sé si mi seguro sigue vigente después de dejar de trabajar?', 'answer' => 'Sigue vigente únicamente si acumulaste las aportaciones necesarias para activar tu derecho especial de latencia (seguro por desempleo). Revisa el portal \"¿Dónde me atiendo?\" para verificar hasta qué fecha exacta el sistema te muestra cobertura activa.', 'keywords' => '["cómo", "seguro", "sigue", "vigente", "después", "dejar", "trabajar"]'],
            ['category_name' => 'Afiliaciones', 'question' => '¿Puedo sacar una cita si no estoy trabajando actualmente?', 'answer' => 'Sí puedes, siempre y cuando te encuentres dentro de tu periodo de cobertura por desempleo (derecho de latencia) o si te has afiliado de manera independiente a un seguro de salud potestativo pagando tus aportes de forma directa.', 'keywords' => '["sacar", "cita", "estoy", "trabajando", "actualmente"]'],
            ['category_name' => 'Afiliaciones', 'question' => '¿Qué tipo de seguro tiene EsSalud?', 'answer' => 'Tiene varios regímenes diseñados para la realidad de cada persona: el Seguro Regular (+Seguro) para trabajadores dependientes en actividad, el Seguro Agrario (para trabajadores del campo), los Seguros Potestativos (afiliaciones voluntarias e independientes) y coberturas complementarias con EPS.', 'keywords' => '["tipo", "seguro", "essalud"]'],
            ['category_name' => 'Afiliaciones', 'question' => '¿Qué es el Seguro Agrario de EsSalud y quiénes pueden acceder?', 'answer' => 'Es un seguro especial con tasas de aporte diferenciadas diseñado para proteger a los trabajadores que realizan actividades de cultivo, crianza de animales o agroindustria, ya sea que trabajen para una empresa del campo (dependientes) o de forma independiente.', 'keywords' => '["seguro", "agrario", "essalud", "quiénes", "pueden", "acceder"]'],
            ['category_name' => 'Afiliaciones', 'question' => '¿Cómo se calcula el subsidio para un trabajador agrario independiente?', 'answer' => 'Para los agrarios independientes, el subsidio diario se calcula en base a la Remuneración Mínima Vital (RMV). Para los agrarios dependientes, se calcula con el promedio de las últimas 4 remuneraciones mensuales antes de la contingencia.', 'keywords' => '["cómo", "calcula", "subsidio", "trabajador", "agrario", "independiente"]'],
            ['category_name' => 'Afiliaciones', 'question' => '¿Qué es la baja temporal de un trabajador portuario?', 'answer' => 'Es un beneficio especial para los trabajadores portuarios. Cuando están en \"baja temporal\" (sin trabajo por un máximo de 3 meses), igual tienen derecho a subsidios como lactancia y sepelio, aunque no tengan vínculo laboral activo, siempre que cumplan con los meses de aporte.', 'keywords' => '["baja", "temporal", "trabajador", "portuario"]'],
            ['category_name' => 'Afiliaciones', 'question' => '¿Qué es el mes de inicio de la contingencia?', 'answer' => 'Es el mes en que ocurre el hecho que te da derecho al subsidio (ejemplo: enfermarse o el nacimiento). Sirve para auditar si cumples con los meses de aporte requeridos.', 'keywords' => '["inicio", "contingencia"]'],
            ['category_name' => 'Afiliaciones', 'question' => '¿Qué requisitos de aporte debo cumplir si soy un trabajador regular?', 'answer' => 'Necesitas tener 3 meses de aportes consecutivos o 4 meses no consecutivos dentro de los 6 meses anteriores al mes en que empezó tu enfermedad, accidente o maternidad. Además, tu empleador debe estar al día con los pagos o en fraccionamiento.', 'keywords' => '["requisitos", "aporte", "debo", "cumplir", "trabajador", "regular"]'],
            ['category_name' => 'Afiliaciones', 'question' => '¿Existen condiciones especiales para los trabajadores agrarios respecto al aporte?', 'answer' => 'Sí. Para los agrarios (dependientes o independientes), los requisitos son más flexibles: necesitan 3 meses consecutivos o 4 no consecutivos pero en los 12 meses anteriores a la contingencia (no solo 6 meses). Y tienen tasas de aporte más bajas según la ley agraria.', 'keywords' => '["existen", "condiciones", "especiales", "trabajadores", "agrarios", "respecto", "aporte"]'],
            ['category_name' => 'Afiliaciones', 'question' => '¿Qué sucede si tengo un accidente y no tengo meses de aporte previos?', 'answer' => 'Si es un accidente (de cualquier tipo, no de trabajo), basta con que estés afiliado para recibir la atención médica desde el primer día sin meses de espera. Pero ojo, esto es para la atención médica. Para el subsidio por incapacidad en dinero sí necesitas cumplir con los aportes de ley.', 'keywords' => '["sucede", "accidente", "meses", "aporte", "previos"]'],
            ['category_name' => 'Afiliaciones', 'question' => '¿Un pensionista tiene que esperar meses de aporte para el subsidio de sepelio?', 'answer' => 'No. Los pensionistas tienen derecho a la prestación por sepelio sin período de carencia desde el momento en que son declarados pensionistas. Además, deben seguir percibiendo su pensión y tener los meses de aporte requeridos (3 consecutivos o 4 no consecutivos en los últimos 6 meses).', 'keywords' => '["pensionista", "esperar", "meses", "aporte", "subsidio", "sepelio"]'],
            ['category_name' => 'Consultas Generales', 'question' => '¿Cómo me afilio al Seguro Potestativo de EsSalud?', 'answer' => 'Se realiza en 3 pasos: 1\) Reúne tu DNI (y el de tus derechohabientes). 2\) Acude a una oficina OSPE de EsSalud y llena el formulario 1010\. 3\) Paga tu primer aporte mensual en el Banco de la Nación (el costo varía por edad entre S/ 132 y S/ 215 aprox.). Las emergencias por accidentes cubren desde el día siguiente del primer pago; enfermedades comunes cubren después de 3 meses pagando seguido. Para que el seguro te cubra el parto, debes estar afiliada y haber pagado 10 meses seguidos antes de que nazca tu bebé (debes estar asegurada desde antes de la concepción; si te afilias ya embarazada, no te cubre el parto). Requisitos: ser la mamá titular del seguro, estar al día en los 10 meses de aportes consecutivos y atenderte en la red de EsSalud. Mantienes la cobertura gratuita por derecho de latencia (de 2 a 12 meses según el cuadro de aportes acumulados de la sección anterior). Después tienes dos opciones: si encuentras un nuevo empleo formal, tu empleador te afilia al Seguro Regular; si pasas a trabajar por tu cuenta, puedes contratar y pagar de forma voluntaria el Seguro Potestativo.', 'keywords' => '["cómo", "afilio", "seguro", "potestativo", "essalud"]'],
            ['category_name' => 'Consultas Generales', 'question' => '¿Es posible darse de baja voluntariamente de un seguro de EsSalud?', 'answer' => 'Sí, pero solo del Seguro Potestativo. El seguro regular de trabajo no se puede cancelar porque es obligatorio. Para la baja del potestativo, presentas una carta formal firmada junto a tu DNI en una oficina OSPE. Si pagaste todo el año por adelantado, EsSalud te devuelve los meses no utilizados aplicando un pequeño descuento por gastos administrativos.', 'keywords' => '["posible", "darse", "baja", "voluntariamente", "seguro", "essalud"]'],
            ['category_name' => 'Consultas Generales', 'question' => '¿Qué es el Seguro Complementario de Trabajos de Riesgo (SCTR)?', 'answer' => 'Es un seguro obligatorio que tu empleador debe contratar si trabajas en actividades consideradas de alto riesgo por la ley (minería, construcción, pesca, industrias). Asegura que si sufres un accidente laboral o enfermedad profesional, EsSalud te atienda al 100% gratis y otorga pensiones por invalidez o indemnizaciones por fallecimiento.', 'keywords' => '["seguro", "complementario", "trabajos", "riesgo", "sctr"]'],
            ['category_name' => 'Consultas Generales', 'question' => '¿Qué cubre el SCTR?', 'answer' => 'Cubre de forma integral todas las prestaciones médicas (consultas, cirugías, hospitalización, medicinas, prótesis y rehabilitación) derivadas de un accidente de trabajo o enfermedad profesional. También cubre pensiones de invalidez para el trabajador o pensiones de sobrevivencia para su familia si este fallece.', 'keywords' => '["cubre", "sctr"]'],
            ['category_name' => 'Consultas Generales', 'question' => '¿Puedo cobrar sepelio si mi familiar falleció por un accidente de trabajo cubierto por el SCTR?', 'answer' => 'No a través del seguro regular. El SCTR ya cuenta con su propia cobertura integral para gastos de sepelio por accidentes de trabajo. Por ende, para evitar duplicidad de beneficios, el seguro regular de EsSalud no pagará otro subsidio por sepelio; la familia debe cobrarlo directamente de la póliza del SCTR.', 'keywords' => '["cobrar", "sepelio", "familiar", "falleció", "accidente", "trabajo", "cubierto", "sctr"]'],
            ['category_name' => 'Consultas Generales', 'question' => '¿Qué temas se tratan en las capacitaciones \"In House\"?', 'answer' => 'Son charlas técnicas dictadas por EsSalud dentro de las empresas enfocadas en la prevención y gestión de seguros: el seguro de accidentes \+Vida, el SCTR (+Protección), el manejo corporativo de la plataforma VIVA, la tramitación correcta de Prestaciones Económicas (subsidios) y programas de \+Promoción de la salud ocupacional.', 'keywords' => '["temas", "tratan", "capacitaciones", "house"]'],
            ['category_name' => 'Consultas Generales', 'question' => '¿Qué beneficio adicional ofrece el seguro \"+ Vida\"?', 'answer' => 'Además de la indemnización principal por muerte o invalidez total/parcial permanente por accidente, incluye beneficios adicionales económicos por luto, un adelanto de cobertura para gastos de sepelio y servicios funerarios básicos (ataúd, carroza, capilla). También otorga cobertura en caso de fallecimiento por accidente de la cónyuge o concubina registrada.', 'keywords' => '["beneficio", "adicional", "ofrece", "seguro", "vida"]'],
            ['category_name' => 'Consultas Generales', 'question' => '¿Qué es el seguro \"+ Protección\" y con qué subsidio se relaciona?', 'answer' => '\"+ Protección\" es la denominación comercial que utiliza EsSalud para su seguro SCTR. Se relaciona de manera directa con la auditoría y pago del subsidio por incapacidad temporal por accidentes o enfermedades laborales, con el subsidio por sepelio y con el otorgamiento de pensiones vitalicias por invalidez.', 'keywords' => '["seguro", "protección", "subsidio", "relaciona"]'],
            ['category_name' => 'Consultas Generales', 'question' => '¿Qué es el \+Vida Seguro de Accidentes de EsSalud?', 'answer' => 'Es un seguro de accidentes personal y voluntario con un costo muy bajo (S/ 5 al mes). Protege al titular y a su cónyuge las 24 horas del día, los 365 días del año (incluso en el extranjero), otorgando una indemnización económica sustancial en caso de invalidez permanente o fallecimiento provocado única y exclusivamente por un accidente (no cubre enfermedades comunes).', 'keywords' => '["vida", "seguro", "accidentes", "essalud"]'],
            ['category_name' => 'Consultas Generales', 'question' => '¿Quiénes pueden afiliarse al \+Vida?', 'answer' => 'Todos los asegurados titulares de EsSalud que tengan entre 15 y 70 años cumplidos, pertenecientes al régimen regular (planilla), seguro agrario, seguro potestativo o pescadores artesanales.', 'keywords' => '["quiénes", "pueden", "afiliarse", "vida"]'],
            ['category_name' => 'Consultas Generales', 'question' => '¿Cuánto cuesta la prima mensual del \+Vida?', 'answer' => 'Tiene un costo de S/ 5.00 mensuales. No se incrementa por criterios de edad ni por el estado médico del afiliado. Lo paga el empleador vía retención de planilla o el independiente directo en el Banco de la Nación.', 'keywords' => '["cuánto", "cuesta", "prima", "mensual", "vida"]'],
            ['category_name' => 'Consultas Generales', 'question' => '¿Qué accidentes cubre el \+Vida?', 'answer' => 'Cubre cualquier evento fortuito, violento y externo que cause la muerte o una invalidez permanente (total o parcial), tales como choques vehiculares, caídas graves, quemaduras graves, electrocución o ahogamiento. Quedan excluidas las muertes o invalideces provocadas por enfermedades comunes.', 'keywords' => '["accidentes", "cubre", "vida"]'],
            ['category_name' => 'Consultas Generales', 'question' => '¿El \+Vida reemplaza mi seguro regular de EsSalud?', 'answer' => 'No, no lo reemplaza. Es un seguro financiero complementario. La atención médica en los hospitales se sigue rigiendo bajo tu seguro regular de salud común. El \+Vida actúa únicamente como un fondo de indemnización económica ante la ocurrencia de un siniestro por accidente.', 'keywords' => '["vida", "reemplaza", "seguro", "regular", "essalud"]'],
            ['category_name' => 'Consultas Generales', 'question' => '¿Cómo me afilio al \+Vida si soy trabajador independiente?', 'answer' => 'Debes llenar el Formulario 6012 detallando tus datos y beneficiarios, presentarlo físicamente en una oficina OSPE de EsSalud para registrar tu contrato y, posteriormente, acudir mensualmente al Banco de la Nación para abonar los S/ 5.00 con tu número de contrato asignado.', 'keywords' => '["cómo", "afilio", "vida", "trabajador", "independiente"]'],
            ['category_name' => 'Consultas Generales', 'question' => '¿Mi empleador puede afiliarme al \+Vida?', 'answer' => 'Sí, los empleadores pueden afiliar colectivamente a sus trabajadores dependientes utilizando el Formulario 6012 firmado por cada empleado, realizando el descuento mensual de los S/ 5.00 directamente en la boleta de pago o asumiéndolo como un beneficio laboral corporativo.', 'keywords' => '["empleador", "puede", "afiliarme", "vida"]'],
            ['category_name' => 'Consultas Generales', 'question' => '¿Cómo designo a mis beneficiarios en el seguro \+Vida? / ¿Los porcentajes de beneficiarios deben sumar exactamente 100%?', 'answer' => 'Se realiza exclusivamente en la sección 3 del Formulario 6012, indicando nombres completos, DNI y asignando un porcentaje exacto de la indemnización a cada uno. Es obligatorio que la sumatoria de todos los porcentajes asignados sea exactamente igual al 100%. De lo contrario, el formulario es rechazado y carece de validez legal.', 'keywords' => '["cómo", "designo", "beneficiarios", "seguro", "vida", "porcentajes", "beneficiarios", "deben"]'],
            ['category_name' => 'Consultas Generales', 'question' => '¿Cuánto se paga en caso de fallecimiento del titular en el seguro \+Vida?', 'answer' => 'La indemnización base por fallecimiento accidental es de aproximadamente S/ 84,080.00 (sujeto a las actualizaciones normativas de la póliza institucional), sumado a los beneficios complementarios de luto y sepelio.', 'keywords' => '["cuánto", "paga", "caso", "fallecimiento", "titular", "seguro", "vida"]'],
            ['category_name' => 'Consultas Generales', 'question' => '¿Hasta qué edad puedo afiliarme al \+Vida?', 'answer' => 'La edad límite de ingreso es desde los 15 años hasta los 70 años cumplidos. Si ya estás afiliado antes de cumplir los 70, puedes permanecer en el seguro de forma continua siempre que no interrumpas tus pagos mensuales.', 'keywords' => '["edad", "afiliarme", "vida"]'],
            ['category_name' => 'Consultas Generales', 'question' => '¿El \+Vida tiene cobertura si viajo al extranjero?', 'answer' => 'Sí, la cobertura es global y protege las 24 horas del día en cualquier parte del mundo. La única excepción regulatoria aplica para los miembros del Cuerpo General de Bomberos Voluntarios del Perú (CGBVP), cuya cobertura se restringe únicamente al territorio nacional durante sus actos de servicio.', 'keywords' => '["vida", "cobertura", "viajo", "extranjero"]'],
            ['category_name' => 'Consultas Generales', 'question' => '¿Qué pasa si no designo beneficiarios en el Formulario 6012?', 'answer' => 'En caso de fallecimiento sin beneficiarios explícitos, la indemnización entrará en disputa legal y se distribuirá estrictamente bajo el orden sucesorio que dicta la ley: 1° cónyuge o concubino legítimo e hijos menores, 2° hijos mayores de edad, 3° padres, 4° hermanos menores y 5° herederos legales declarados por sucesión intestada.', 'keywords' => '["pasa", "designo", "beneficiarios", "formulario"]'],
            ['category_name' => 'Consultas Generales', 'question' => '¿Qué pasa si dejo de pagar la prima mensual del seguro \+Vida? / ¿Hay período de gracia?', 'answer' => 'El seguro \+Vida no contempla periodos de gracia ni coberturas provisionales por atraso. Si la prima no se paga en la fecha exacta de vencimiento, la cobertura queda suspendida de forma automática a partir del día siguiente. Si ocurre un siniestro durante el periodo de impago, EsSalud rechazará de oficio la indemnización. La cobertura solo se reactivará para accidentes futuros una vez regularizado el abono.', 'keywords' => '["pasa", "dejo", "pagar", "prima", "mensual", "seguro", "vida", "período"]'],
            ['category_name' => 'Consultas Generales', 'question' => '¿Cómo cobra la indemnización la familia en caso de fallecimiento en el seguro \+Vida?', 'answer' => 'Los beneficiarios de la póliza deben acudir a una oficina OSPE de EsSalud presentando el Formulario 6012 original emitido, el acta de defunción del titular, copia de los documentos de identidad y los documentos que acrediten el vínculo (actas de matrimonio o nacimiento) para que la auditoría autorice la orden de pago bancaria.', 'keywords' => '["cómo", "cobra", "indemnización", "familia", "caso", "fallecimiento", "seguro", "vida"]'],
            ['category_name' => 'Consultas Generales', 'question' => '¿Para qué sirve el Formulario 6012 de EsSalud? / ¿Cómo se llena correctamente?', 'answer' => 'Sirve para formalizar la afiliación al seguro \+Vida, registrar los datos de la cónyuge/concubina para su cobertura y declarar formalmente a los beneficiarios de la indemnización. Debe llenarse con letra de imprenta clara, sin borrones, de manera legible y sin usar corrector líquido (estos factores invalidan por completo el documento). Las firmas deben coincidir fielmente con el DNI.', 'keywords' => '["sirve", "formulario", "essalud", "cómo", "llena", "correctamente"]'],
            ['category_name' => 'Consultas Generales', 'question' => '¿Puedo registrar a mi concubino(a) como beneficiario en el \+Vida?', 'answer' => 'Sí, es perfectamente legal, pero requiere un sustento formal para la auditoría: la unión de hecho debe estar inscrita y reconocida formalmente mediante Escritura Pública Notarial o por Resolución Judicial inscrita en los Registros Públicos (SUNARP). No se validan declaraciones simples de convivencia.', 'keywords' => '["registrar", "concubino", "beneficiario", "vida"]'],
            ['category_name' => 'Consultas Generales', 'question' => '¿Puedo cambiar mis beneficiarios después de haber entregado el formulario 6012?', 'answer' => 'Sí, puedes modificar tu declaración las veces que consideres necesario. Solo debes llenar y firmar un nuevo Formulario 6012 con la nueva distribución de beneficiarios y presentarlo en la OSPE. Ante una auditoría por siniestro, el último formulario ingresado y sellado por EsSalud es el único que posee validez legal.', 'keywords' => '["cambiar", "beneficiarios", "después", "haber", "entregado", "formulario"]'],
            ['category_name' => 'Consultas Generales', 'question' => '¿Necesito el RUC de mi empleador para llenar el formulario 6012?', 'answer' => 'Es obligatorio únicamente si eres un trabajador regular dependiente en planilla, registrándolo en la sección de datos del empleador. Si realizas una afiliación como trabajador independiente, dejas esa casilla completamente en blanco.', 'keywords' => '["empleador", "llenar", "formulario"]'],
            ['category_name' => 'Consultas Generales', 'question' => '¿Para qué sirve el Formulario 6004 de EsSalud y quiénes deben usarlo?', 'answer' => 'Sirve exclusivamente para que un trabajador independiente que realiza actividades económicas de alto riesgo (según el listado de ley) se afilie de forma voluntaria al seguro SCTR (+Protección) administrado por EsSalud, permitiendo registrar su contrato y generar sus aportes mensuales.', 'keywords' => '["sirve", "formulario", "essalud", "quiénes", "deben", "usarlo"]'],
            ['category_name' => 'Consultas Generales', 'question' => '¿Es obligatorio tener RUC para afiliarme al SCTR como trabajador independiente?', 'answer' => 'Sí, es un requisito indispensable y obligatorio. El Registro Único de Contribuyentes (RUC) debe encontrarse en estado activo y habido ante la SUNAT bajo la modalidad de persona natural con negocio, debiendo presentar la ficha RUC de SUNAT impresa junto al Formulario 6004\.', 'keywords' => '["obligatorio", "tener", "afiliarme", "sctr", "trabajador", "independiente"]'],
            ['category_name' => 'Consultas Generales', 'question' => '¿Puedo hacer el trámite de afiliación al SCTR por internet o puede ir otra persona por mí?', 'answer' => 'No, bajo ninguna circunstancia. El trámite de afiliación independiente al SCTR es estrictamente presencial y personalísimo. El trabajador interesado debe acudir físicamente a la oficina OSPE portando su DNI original para la validación de su identidad y firma en el contrato. No se aceptan apoderados, familiares ni cartas poder.', 'keywords' => '["trámite", "afiliación", "sctr", "internet", "puede", "otra", "persona"]'],
            ['category_name' => 'Consultas Generales', 'question' => '¿Qué pasa si mi actividad no está en la lista de alto riesgo del Anexo 5? / ¿Cómo sé si mi actividad económica es de alto riesgo?', 'answer' => 'Debes confrontar tu actividad laboral con el listado oficial del Anexo 5 del Decreto Supremo N° 009-97-SA. Si tu labor (minería, construcción, pesca, etc.) no figura textualmente en dicho anexo, la ley no te califica como trabajador de alto riesgo y EsSalud no te permitirá afiliarte al régimen del SCTR.', 'keywords' => '["pasa", "actividad", "está", "lista", "alto", "riesgo", "anexo", "cómo"]'],
            ['category_name' => 'Consultas Generales', 'question' => '¿Qué es el código CIIU y dónde lo encuentro?', 'answer' => 'Es la Clasificación Industrial Internacional Uniforme, un código numérico internacional que identifica la actividad económica exacta de un contribuyente. Lo encuentras detallado en tu ficha RUC de SUNAT. Al rellenar el Formulario 6004, la plataforma te exigirá ingresar los primeros 5 dígitos correspondientes a tu actividad principal declarada.', 'keywords' => '["código", "ciiu", "dónde", "encuentro"]'],
            ['category_name' => 'Consultas Generales', 'question' => '¿Qué hago si no sé cuál es mi nivel de riesgo en el SCTR?', 'answer' => 'No te preocupes. Al momento de entregar tus documentos de forma presencial, el personal de auditoría de la OSPE evaluará tu actividad CIIU declarada en tu RUC y te asignará técnicamente la tasa de riesgo correspondiente según la escala de ley (Nivel I, II, III o IV).', 'keywords' => '["hago", "cuál", "nivel", "riesgo", "sctr"]'],
            ['category_name' => 'Consultas Generales', 'question' => '¿Cómo y dónde pago el aporte del SCTR si soy trabajador independiente?', 'answer' => 'Se paga de manera mensual y obligatoria en las ventanillas del Banco de la Nación. Al momento de pagar debes indicar que vas a abonar el SCTR de EsSalud y proporcionar de forma exacta el número de contrato que te fue asignado en la OSPE. Puedes realizar pagos adelantados de varios meses si lo deseas para asegurar la continuidad de tu cobertura.', 'keywords' => '["cómo", "dónde", "pago", "aporte", "sctr", "trabajador", "independiente"]'],
            ['category_name' => 'Consultas Generales', 'question' => '¿Cuánto tengo que pagar de aporte mensual al SCTR como trabajador independiente? / ¿Cómo afecta la UIT?', 'answer' => 'El costo es variable y cambia de forma anual debido a que la base de cálculo legal equivale exactamente a la mitad de una Unidad Impositiva Tributaria (UIT) vigente, multiplicada por la tasa porcentual asignada a tu nivel de riesgo específico.', 'keywords' => '["cuánto", "pagar", "aporte", "mensual", "sctr", "trabajador", "independiente", "cómo"]'],
            ['category_name' => 'Consultas Generales', 'question' => '¿Qué pasa si no pago el aporte mensual del SCTR independiente?', 'answer' => 'La penalidad es inmediata: la cobertura médica y económica del SCTR se suspende por completo durante todo el mes que se encuentre en condición de impago. Si sufres un accidente laboral en esos días, estarás completamente desprotegido y el seguro regular común de EsSalud no asumirá los costos especializados de riesgo, procediendo a facturar las atenciones de forma particular.', 'keywords' => '["pasa", "pago", "aporte", "mensual", "sctr", "independiente"]'],
            ['category_name' => 'Consultas Generales', 'question' => '¿Cómo obtengo mi número de contrato del SCTR y qué pasa si lo pierdo?', 'answer' => 'El número de contrato de aportes te lo entrega el asesor de EsSalud el mismo día en que completas con éxito tu afiliación presencial con el Formulario 6004\. Es un dato crítico ya que el Banco de la Nación no tiene acceso a la base de datos de EsSalud para buscarlo por DNI. Si lo pierdes, estás obligado a acudir nuevamente de forma presencial a la oficina OSPE para que un asesor busque tu registro interno en el sistema informático y te lo vuelva a facilitar.', 'keywords' => '["cómo", "obtengo", "número", "contrato", "sctr", "pasa", "pierdo"]'],
            ['category_name' => 'Consultas Generales', 'question' => '¿La cobertura del SCTR entra en vigencia el mismo día que me afilio y pago?', 'answer' => 'Sí, la cobertura técnica se activa a partir del momento en que realizas el pago de tu primera prima mensual en el Banco de la Nación. Sin embargo, audita rigurosamente que el seguro solo brinda cobertura a aquellos accidentes laborales o contingencias médicas que ocurran con fecha posterior al pago del aporte; no cubre siniestros ocurridos de forma previa al abono del dinero.', 'keywords' => '["cobertura", "sctr", "entra", "vigencia", "mismo", "afilio", "pago"]'],
            ['category_name' => 'Consultas Generales', 'question' => '¿El SCTR cubre accidentes fuera del horario de trabajo o durante el trayecto a mi casa?', 'answer' => 'No. La cobertura del SCTR es de carácter estrictamente operacional: solo cubre aquellos accidentes que ocurran de forma directa mientras ejecutas las funciones de tu puesto de trabajo de alto riesgo. Quedan totalmente excluidos los accidentes ocurridos en tu hogar, durante tus tiempos libres, periodos de vacaciones o en el trayecto de ida y vuelta (ruta domicilio-trabajo).', 'keywords' => '["sctr", "cubre", "accidentes", "fuera", "horario", "trabajo", "durante", "trayecto"]'],
            ['category_name' => 'Consultas Generales', 'question' => '¿El SCTR cubre enfermedades profesionales o solo accidentes de trabajo? / ¿Qué tipos cubre?', 'answer' => 'Cubre de igual manera ambas contingencias: accidentes imprevistos en zona de labor y enfermedades profesionales crónicas desarrolladas a causa del entorno laboral. Para ser validadas por la auditoría médica, las enfermedades deben figurar de forma estricta en la lista oficial del Ministerio de Salud (Resolución Ministerial N° 480-2008/MINSA), tales como la hipoacusia inducida por ruido, la neumoconiosis por inhalación de polvos minerales o intoxicaciones crónicas por manipulación de agentes químicos.', 'keywords' => '["sctr", "cubre", "enfermedades", "profesionales", "solo", "accidentes", "trabajo", "tipos"]'],
            ['category_name' => 'Consultas Generales', 'question' => '¿Qué significa que los formularios de afiliación posean carácter de Declaración Jurada?', 'answer' => 'Tiene un peso legal crítico. Significa que el usuario declara bajo juramento administrativo que toda la información consignada (ingresos, de negocios, actividades, estados de salud o datos de beneficiarios) es verídica y fiel a la realidad. Si una fiscalización o auditoría posterior detecta falsedad, adulteración u ocultamiento de información, EsSalud anulará inmediatamente los contratos y seguros, y procederá a interponer una denuncia de carácter penal ante el Ministerio Público por el delito de fraude contra la administración pública y falsificación de documentos públicos.', 'keywords' => '["significa", "formularios", "afiliación", "posean", "carácter", "declaración", "jurada"]'],
        ];

        $inserted = 0;
        $skipped = 0;

        foreach ($newFaqs as $faq) {
            $questionTrimmed = trim($faq['question']);

            if (in_array($questionTrimmed, $existingQuestions)) {
                $skipped++;
                continue;
            }

            $cat = $categories->get($faq['category_name']);
            Faq::create([
                'category_id' => $cat?->id,
                'question' => $faq['question'],
                'answer' => $faq['answer'],
                'keywords' => $faq['keywords'],
                'is_active' => true,
            ]);
            $inserted++;
        }

        $this->command->info("FAQs V2: {$inserted} inserted, {$skipped} skipped (already exist).");
    }
}
